{
  "name": "Mantrailing Card App",
  "description": "A web application for managing Mantrailing Card customers, balances, transactions, and training progress."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import { HashRouter } from 'react-router-dom';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <HashRouter>
      <App />
    </HashRouter>
  </React.StrictMode>
);

export interface Customer {
  id: string;
  avatarInitials: string;
  avatarColor: string;
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  dogName: string;
  chipNumber: string;
  balance: number;
  totalTransactions: number;
  level: TrainingLevelEnum;
  createdAt: string; // Date string (e.g., '9.2.2025')
  createdBy: string;
  qrCodeData: string; // URL for QR code image
  documents: Document[];
  trainingProgress: TrainingSection[];
}

export interface Transaction {
  id: string;
  customerId: string;
  type: 'recharge' | 'debit';
  description: string;
  amount: number;
  date: string; // Date string (e.g., '22.12.2025')
  employee: string;
}

export enum TrainingLevelEnum {
  EINSTEIGER = 'Einsteiger',
  GRUNDLAGEN = 'Grundlagen',
  FORTGESCHRITTENE = 'Fortgeschrittene',
  MASTERCLASS = 'Masterclass',
}

export interface TrainingSection {
  id: number;
  name: TrainingLevelEnum;
  requiredHours: number;
  completedHours: number;
  status: 'Aktuell' | 'Gesperrt' | 'Abgeschlossen';
}

export interface Document {
  id: string;
  name: string;
  url: string;
}

export interface StatCardProps {
  title: string;
  value: string | number;
  icon: React.ElementType; // SVG component
  color: string; // Tailwind color class
  description?: string;
}

export interface NavigationItem {
  path: string;
  label: string;
  icon: React.ElementType; // SVG component
}

export interface CustomerTableData {
  id: string;
  avatarInitials: string;
  avatarColor: string;
  name: string;
  dog: string;
  balance: number;
  level: TrainingLevelEnum;
  createdAt: string;
}

export interface TransactionConfirmationData {
