import React, { useState } from 'react';
import Card from '../components/Card';
import StatCard from '../components/StatCard';
import Table from '../components/Table';
import Button from '../components/Button';
import Avatar from '../components/Avatar';
import { PlusIcon, ChevronRightIcon, UsersIcon, ChartPieIcon, ClipboardDocumentListIcon, UserCircleIcon } from '../components/Icons';
import { MOCK_CUSTOMERS, ALPHABET, MOCK_DASHBOARD_STATS } from '../constants';
import { Customer, CustomerTableData, TrainingLevelEnum } from '../types';
import { useNavigate } from 'react-router-dom';

const CustomerManagement: React.FC = () => {
  const navigate = useNavigate();
  const [activeFilter, setActiveFilter] = useState<string>('Alle');

  const filteredCustomers = MOCK_CUSTOMERS.filter((customer) => {
    if (activeFilter === 'Alle') {
      return true;
    }
    return customer.lastName.startsWith(activeFilter);
  });

  const customerTableData: CustomerTableData[] = filteredCustomers.map((customer) => ({
    id: customer.id,
    avatarInitials: customer.avatarInitials,
    avatarColor: customer.avatarColor,
    name: `${customer.firstName} ${customer.lastName}\n${customer.id}`, // Display ID below name
    dog: customer.dogName,
    balance: customer.balance,
    level: customer.level,
    createdAt: customer.createdAt,
  }));

  const columns = [
    {
      key: 'name',
      header: 'Kunde',
      render: (item: CustomerTableData) => (
        <div className="flex items-center">
          <Avatar initials={item.avatarInitials} color={item.avatarColor} size="md" className="mr-3" />
          <div>
            <p className="font-medium text-gray-900">{item.name.split('\n')[0]}</p>
            <p className="text-sm text-gray-500">{item.name.split('\n')[1]}</p>
          </div>
        </div>
      ),
    },
    { key: 'dog', header: 'Hund' },
    {
      key: 'balance',
      header: 'Guthaben',
      render: (item: CustomerTableData) => item.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' }),
    },
    {
      key: 'level',
      header: 'Level',
      render: (item: CustomerTableData) => (
        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
          {item.level}
        </span>
      ),
    },
    { key: 'createdAt', header: 'Erstellt' },
    {
      key: 'actions',
      header: '',
      render: (item: CustomerTableData) => (
        <ChevronRightIcon className="h-5 w-5 text-gray-400" />
      ),
      className: 'text-right',
    },
  ];

  const handleRowClick = (customerData: CustomerTableData) => {
    navigate(`/customers/${customerData.id}`);
  };

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <div className="flex justify-between items-center mb-2">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Kundenverwaltung</h1>
          <p className="text-gray-600">Verwalten Sie alle Ihre Kunden an einem Ort</p>
        </div>
        <Button variant="success" icon={PlusIcon}>
          Neuer Kunde
        </Button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 my-8">
        <StatCard
          title="Kunden Gesamt"
          value={MOCK_CUSTOMERS.length}
          icon={UsersIcon}
          color="bg-green-100 text-green-700"
        />
        <StatCard
          title="Aktiv"
          value={MOCK_CUSTOMERS.filter(c => c.balance > 0).length} // Simple active logic
          icon={ChartPieIcon} // Using ChartPieIcon for now, perhaps a heart for "active"
          color="bg-orange-100 text-orange-700"
        />
        <StatCard
          title="Guthaben"
          value={MOCK_CUSTOMERS.reduce((sum, c) => sum + c.balance, 0).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
          icon={ClipboardDocumentListIcon}
          color="bg-blue-100 text-blue-700"
        />
        <StatCard
          title="Transaktionen Monat"
          value={MOCK_TRANSACTIONS.filter(t => t.date.includes('2025')).length} // Simple month filter
          icon={UserCircleIcon}
          color="bg-purple-100 text-purple-700"
        />
      </div>

      {/* Alphabet Filter */}
      <Card className="mb-6 px-4 py-2">
        <div className="flex flex-wrap justify-between gap-2">
          <button
            onClick={() => setActiveFilter('Alle')}
            className={`px-3 py-1.5 rounded-md text-sm font-medium transition-colors
              ${activeFilter === 'Alle' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
          >
            Alle
          </button>
          {ALPHABET.map((letter) => (
            <button
              key={letter}
              onClick={() => setActiveFilter(letter)}
              className={`px-3 py-1.5 rounded-md text-sm font-medium transition-colors
                ${activeFilter === letter ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
            >
              {letter}
            </button>
          ))}
        </div>
      </Card>

      {/* Customer List Table */}
      <Card>
        <h2 className="text-xl font-semibold text-gray-900 mb-4">Kundenliste ({filteredCustomers.length})</h2>
        <Table data={customerTableData} columns={columns} onRowClick={handleRowClick} />
      </Card>
    </div>
  );
};

export default CustomerManagement;

