import React, { useState } from 'react';
import Card from '../components/Card';
import StatCard from '../components/StatCard';
import Button from '../components/Button';
import Select from '../components/Select';
import Avatar from '../components/Avatar'; // Import Avatar
import { MOCK_REPORT_TYPES, MOCK_REPORT_PERIODS, MOCK_REPORT_EMPLOYEES, MOCK_TRANSACTIONS, MOCK_CUSTOMERS, MOCK_REPORT_STATS } from '../constants';
import { ArrowUpCircleIcon, ArrowDownCircleIcon } from '../components/Icons';

const Reports: React.FC = () => {
  const [reportType, setReportType] = useState('Monatlich');
  const [timePeriod, setTimePeriod] = useState('Dezember 2025');
  const [employee, setEmployee] = useState('Alle Mitarbeiter');

  // Filter transactions based on selected criteria
  const filteredTransactions = MOCK_TRANSACTIONS.filter(t => {
    const matchesPeriod = timePeriod === 'Gesamt' || t.date.includes(timePeriod.split(' ')[0]) || t.date.includes(timePeriod.split(' ')[1]);
    const matchesEmployee = employee === 'Alle Mitarbeiter' || t.employee === employee;
    return matchesPeriod && matchesEmployee;
  });

  const getTopCustomers = () => {
    const customerTransactions: { [key: string]: { count: number; totalAmount: number } } = {};
    filteredTransactions.forEach(t => {
      if (!customerTransactions[t.customerId]) {
        customerTransactions[t.customerId] = { count: 0, totalAmount: 0 };
      }
      customerTransactions[t.customerId].count++;
      customerTransactions[t.customerId].totalAmount += Math.abs(t.amount); // Consider total value
    });

    return Object.entries(customerTransactions)
      .sort(([, a], [, b]) => b.totalAmount - a.totalAmount) // Sort by total amount spent
      .slice(0, 3) // Get top 3
      .map(([customerId, data]) => {
        const customer = MOCK_CUSTOMERS.find(c => c.id === customerId);
        return {
          customerName: customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt',
          dogName: customer?.dogName || '',
          transactionCount: data.count,
          totalAmount: data.totalAmount,
          avatarInitials: customer?.avatarInitials || '?',
          avatarColor: customer?.avatarColor || 'bg-gray-400',
          id: customerId, // Added for key prop
        };
      });
  };

  const topCustomers = getTopCustomers();

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <h1 className="text-3xl font-bold text-gray-900 mb-2">Berichte & Statistiken</h1>
      <p className="text-gray-600 mb-8">Analysieren und exportieren Sie Ihre Geschäftsdaten</p>

      {/* Filters and Export Buttons */}
      <Card className="mb-8">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 items-end">
          <Select
            id="reportType"
            label="Berichtstyp"
            options={MOCK_REPORT_TYPES.map(type => ({ value: type, label: type }))}
            value={reportType}
            onChange={(e) => setReportType(e.target.value)}
          />
          <Select
            id="timePeriod"
            label="Zeitraum"
            options={MOCK_REPORT_PERIODS.map(period => ({ value: period, label: period }))}
            value={timePeriod}
            onChange={(e) => setTimePeriod(e.target.value)}
          />
          <Select
            id="employee"
            label="Mitarbeiter"
            options={MOCK_REPORT_EMPLOYEES.map(emp => ({ value: emp, label: emp }))}
            value={employee}
            onChange={(e) => setEmployee(e.target.value)}
          />
          <Button variant="outline" className="w-full lg:w-auto">
            Als CSV exportieren
          </Button>
          <Button variant="success" className="w-full lg:w-auto">
            Als PDF exportieren
          </Button>
        </div>
      </Card>

      {/* Stats Cards for Reports */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {MOCK_REPORT_STATS.map((stat, index) => (
          <StatCard
            key={index}
            title={stat.title}
            value={stat.value}
            icon={stat.icon}
            color={stat.color}
          />
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Transaktionen im Zeitraum */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Transaktionen im Zeitraum ({filteredTransactions.length})</h2>
          <div className="space-y-4">
            {filteredTransactions.length === 0 ? (
              <p className="text-gray-500">Keine Transaktionen für den ausgewählten Zeitraum und Mitarbeiter gefunden.</p>
            ) : (
              filteredTransactions.map((transaction) => {
                const customer = MOCK_CUSTOMERS.find(c => c.id === transaction.customerId);
                const isRecharge = transaction.type === 'recharge';
                const IconComponent = isRecharge ? ArrowUpCircleIcon : ArrowDownCircleIcon; // Renamed to IconComponent
                const iconColor = isRecharge ? 'text-green-500' : 'text-red-500';
                const amountColor = isRecharge ? 'text-green-700' : 'text-red-700';
                const amountSign = isRecharge ? '+' : '';

                return (
                  <div key={transaction.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div className="flex items-center">
                      <span className={`p-2 rounded-full bg-gray-200 mr-3 ${iconColor}`}>
                        <IconComponent className="h-5 w-5" /> {/* Used IconComponent */}
                      </span>
                      <div>
                        <p className="font-medium text-gray-900">{transaction.description}</p>
                        <p className="text-sm text-gray-500">
                          {transaction.date} von {transaction.employee}
                          {customer && ` für ${customer.firstName} ${customer.lastName}`}
                        </p>
                      </div>
                    </div>
                    <p className={`font-semibold ${amountColor}`}>
                      {amountSign}{transaction.amount.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                    </p>
                  </div>
                );
              })
            )}
          </div>
        </Card>

        {/* Top Kunden im Zeitraum */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Top Kunden im Zeitraum</h2>
          <div className="space-y-4">
            {topCustomers.length === 0 ? (
              <p className="text-gray-500">Keine Top-Kunden für den ausgewählten Zeitraum und Mitarbeiter gefunden.</p>
            ) : (
              topCustomers.map((customer, index) => (
                <div key={customer.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <div className="flex items-center">
                    <span className="text-lg font-bold text-gray-700 mr-3">{index + 1}.</span>
                    <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="md" className="mr-3" />
                    <div>
                      <p className="font-medium text-gray-900">{customer.customerName}</p>
                      <p className="text-sm text-gray-500">
                        {customer.dogName} &bull; {customer.transactionCount} Transaktion{customer.transactionCount !== 1 ? 'en' : ''}
                      </p>
                    </div>
                  </div>
                  <p className="font-semibold text-gray-800">
                    {customer.totalAmount.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                  </p>
                </div>
              ))
            )}
          </div>
        </Card>
      </div>
    </div>
  );
};

export default Reports;

