interface SidebarProps {
  appName: string;
}

const Sidebar: React.FC<SidebarProps> = ({ appName }) => {
  const [isOpen, setIsOpen] = useState(false); // For mobile sidebar toggle

  const toggleSidebar = () => {
    setIsOpen(!isOpen);
  };

  return (
    <>
      {/* Mobile Menu Button */}
      <button
        onClick={toggleSidebar}
        className="fixed bottom-4 left-4 z-40 p-3 bg-blue-600 text-white rounded-full shadow-lg md:hidden"
        aria-label="Toggle navigation"
      >
        <svg
          className="h-6 w-6"
          xmlns="http://www.w3.org/2000/svg"
          fill="none"
          viewBox="0 0 24 24"
          stroke="currentColor"
        >
          {isOpen ? (
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          ) : (
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h16M4 18h16" />
          )}
        </svg>
      </button>

      {/* Backdrop for mobile */}
      {isOpen && (
        <div
          className="fixed inset-0 bg-black bg-opacity-50 z-30 md:hidden"
          onClick={toggleSidebar}
        ></div>
      )}

      {/* Sidebar */}
      <aside
        className={`fixed inset-y-0 left-0 w-64 bg-[#00A1D6] text-white flex flex-col z-40 transition-transform duration-300 ease-in-out
          ${isOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}
      >
        <div className="p-6 text-2xl font-bold flex-shrink-0">
          {appName}
        </div>

        <nav className="flex-grow p-4 space-y-2">
          {/* Status indicators removed */}
          {NAVIGATION_ITEMS.map((item) => (
            <NavLink
              key={item.path}
              to={item.path}
              className={({ isActive }) =>
                `flex items-center space-x-3 p-3 rounded-lg transition-colors duration-200 group
                 ${isActive ? 'bg-blue-500 text-white shadow-md' : 'text-white hover:bg-white/10'}`
              }
              onClick={() => setIsOpen(false)} // Close sidebar on navigation for mobile
            >
              <item.icon className="h-6 w-6 text-white group-hover:text-white" />
              <span className="text-lg">{item.label}</span>
            </NavLink>
          ))}
        </nav>
      </aside>
    </>
  );
};

export default Sidebar;

import React from 'react';
import Modal from './Modal';
import Button from './Button';
import { CheckCircleIcon, XMarkIcon } from './Icons'; 
import { TransactionConfirmationData } from '../types';

interface TransactionConfirmationModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: () => void;
  data: TransactionConfirmationData | null;
}

const TransactionConfirmationModal: React.FC<TransactionConfirmationModalProps> = ({
  isOpen,
  onClose,
  onConfirm,
  data,
}) => {
  if (!data) return null;

  const isRecharge = data.transactionType === 'Aufladung';
  const amountColor = isRecharge ? 'text-green-600' : 'text-red-600';

  return (
    <Modal isOpen={isOpen} onClose={onClose} className="max-w-xl">
      <div className="p-0">
        <div className="bg-green-100 p-4 rounded-t-lg flex items-center justify-between">
          <div className="flex items-center">
            <CheckCircleIcon className="h-6 w-6 text-green-600 mr-2" />
            <h3 className="text-lg font-semibold text-green-800">Transaktion bestätigen</h3>
          </div>
          <button
            type="button"
            className="text-green-600 hover:text-green-800 focus:outline-none"
            onClick={onClose}
          >
            <span className="sr-only">Close modal</span>
            <XMarkIcon className="h-5 w-5" />
          </button>
        </div>

        <div className="p-6 space-y-5">
          <p className="text-gray-700">Bitte bestätigen Sie die Transaktion für <span className="font-semibold">{data.customerName}</span>.</p>

          <div className="bg-blue-50 text-blue-800 p-3 rounded-lg flex items-center">
            <CheckCircleIcon className="h-5 w-5 mr-2" />
            <span>Mitarbeiter: <span className="font-medium">{data.employee}</span></span>
          </div>

          <div className="space-y-3">
            <div className="flex justify-between items-center text-gray-700">
              <span>{data.transactionType}</span>
              <span className={`font-semibold ${amountColor}`}>
                {data.transactionType === 'Aufladung' ? '+' : ''}{data.amount.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
              </span>
            </div>
            <div className="flex justify-between items-center text-lg font-bold text-gray-900 border-t pt-3 border-gray-200">
              <span>Gesamt gutgeschrieben</span>
              <span className={amountColor}>
                {data.transactionType === 'Aufladung' ? '+' : ''}{data.amount.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
              </span>
            </div>
          </div>

          <div className="bg-gray-50 p-4 rounded-lg flex justify-between items-center text-sm">
            <div>
              <p className="text-gray-500">Alter Saldo</p>
              <p className="font-semibold text-gray-900">{data.oldBalance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</p>
            </div>
            <div className="text-gray-500 text-lg mx-4">&rarr;</div>
            <div>
              <p className="text-gray-500">Neuer Saldo</p>
              <p className="font-bold text-blue-600 text-lg">{data.newBalance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</p>
            </div>
          </div>
        </div>

        <div className="p-4 border-t border-gray-200 flex justify-end space-x-3">
          <Button variant="outline" onClick={onClose}>
            Abbrechen
          </Button>
          <Button variant="success" onClick={onConfirm} icon={CheckCircleIcon}>
            Bestätigen und Buchen
          </Button>
        </div>
      </div>
    </Modal>
  );
};

export default TransactionConfirmationModal;

