  className?: string;
}

const TrainingPawIcon: React.FC<TrainingHourCircleProps> = ({ filled, className = '' }) => (
  // Updated to use image from URL for filled state, and a placeholder for unfilled
  <div className={`flex items-center justify-center h-8 w-8 ${className}`}>
    {filled ? (
      <img
        src="https://hs-bw.com/wp-content/uploads/2025/12/Suchund-Icon.png"
        alt="Completed Training Hour"
        className="h-full w-full object-contain"
      />
    ) : (
      <div className="h-full w-full rounded-full bg-gray-200 border border-gray-300 flex items-center justify-center text-xs text-gray-500">
        {/* Optional: Add a subtle indicator for unfilled */}
      </div>
    )}
  </div>
);


const CustomerDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [showModal, setShowModal] = useState(false);
  const [transactionData, setTransactionData] = useState<TransactionConfirmationData | null>(null);

  const customer = MOCK_CUSTOMERS.find((c) => c.id === id);

  if (!customer) {
    return (
      <div className="p-8 text-center text-red-600">
        Kunde mit ID "{id}" nicht gefunden.
        <Button variant="primary" onClick={() => navigate('/customers')} className="mt-4">
          Zurück zur Kundenliste
        </Button>
      </div>
    );
  }

  const handleOpenModal = (amount: number, type: 'Aufladung' | 'Abbuchung') => {
    const oldBalance = customer.balance;
    const newBalance = type === 'Aufladung' ? oldBalance + amount : oldBalance - amount;
    setTransactionData({
      customerId: customer.id,
      customerName: `${customer.firstName} ${customer.lastName}`,
      employee: CURRENT_EMPLOYEE,
      transactionType: type,
      amount: amount,
      oldBalance: oldBalance,
      newBalance: newBalance,
    });
    setShowModal(true);
  };

  const handleConfirmTransaction = () => {
    // In a real app, this would update the backend/state
    console.log('Transaction confirmed:', transactionData);
    // For now, just close the modal.
    setShowModal(false);
    setTransactionData(null);
    // Simulate updating customer balance, would require re-fetching or state management
    // customer.balance = transactionData.newBalance; // This would directly mutate, not ideal in React
    // Consider adding a simple "success" toast message.
  };

  const getStatusClasses = (status: string) => {
    switch (status) {
      case 'Aktuell':
        return 'bg-green-100 text-green-800';
      case 'Gesperrt':
        return 'bg-red-100 text-red-800';
      case 'Abgeschlossen':
        return 'bg-blue-100 text-blue-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  return (
    <div className="p-6 md:p-8 lg:p-10 min-h-screen">
      <div className="flex items-center justify-between mb-6 flex-wrap gap-4">
        <div className="flex items-center">
          <button onClick={() => navigate('/customers')} className="text-gray-500 hover:text-gray-700 mr-4">
            <ArrowLeftIcon className="h-6 w-6" />
          </button>
          <h1 className="text-2xl font-bold text-gray-900 flex items-center">
            {customer.firstName} {customer.lastName}
            <span className="text-gray-500 font-normal text-base ml-2">Kundendetails & Übersicht</span>
          </h1>
        </div>
        <div className="flex space-x-3">
          <Button variant="outline">Stammdaten</Button>
          <Button variant="success" onClick={() => handleOpenModal(215, 'Aufladung')}>
            Guthaben verwalten
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column */}
        <div className="lg:col-span-2 space-y-6">
          {/* Persönliche Daten */}
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Persönliche Daten</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-x-6 gap-y-4 items-center">
              {/* Avatar - spans 1 column on all sizes for consistent placement */}
              <div className="col-span-1 flex items-center justify-center sm:justify-start mb-4 sm:mb-0">
                <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="lg" className="mr-4" />
              </div>

              {/* Vorname */}
              <div className="col-span-1">
                <p className="text-sm font-medium text-gray-500">Vorname:</p>
                <p className="font-semibold text-gray-900">{customer.firstName}</p>
              </div>

              {/* Nachname */}
              <div className="col-span-1">
                <p className="text-sm font-medium text-gray-500">Nachname:</p>
                <p className="font-semibold text-gray-900">{customer.lastName}</p>
              </div>

              {/* Email */}
              <div className="col-span-1">
                <p className="text-sm font-medium text-gray-500">Email:</p>
                <div className="flex items-center mt-1">
                  <MailIcon className="h-5 w-5 text-gray-500 mr-2" />
                  <p className="text-gray-900 truncate">{customer.email}</p>
                </div>
              </div>

              {/* Telefon */}
              <div className="col-span-1">
                <p className="text-sm font-medium text-gray-500">Telefon:</p>
                <div className="flex items-center mt-1">
                  <PhoneIcon className="h-5 w-5 text-gray-500 mr-2" />
                  <p className="text-gray-900">{customer.phone}</p>
                </div>
              </div>

              {/* Hund */}
              <div className="col-span-1">
                <p className="text-sm font-medium text-gray-500">Hund:</p>
                <div className="flex items-center mt-1">
                  <HeartIcon className="h-5 w-5 text-gray-500 mr-2" />
                  <p className="font-semibold text-gray-900">{customer.dogName}</p>
                </div>
              </div>

              {/* Chipnummer */}
              <div className="col-span-1">
                <p className="text-sm font-medium text-gray-500">Chipnummer:</p>
                <div className="flex items-center mt-1">
                  <CreditCardIcon className="h-5 w-5 text-gray-500 mr-2" />
                  <p className="font-semibold text-gray-900">{customer.chipNumber}</p>
                </div>
              </div>
            </div>
          </Card>

          {/* Konto-Übersicht (Summary Cards) */}
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Konto-Übersicht</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="bg-green-50 p-4 rounded-lg flex flex-col justify-center items-center text-center">
                <p className="text-sm text-gray-600 mb-1">Aktuelles Guthaben</p>
                <p className="text-2xl font-bold text-green-700">{customer.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</p>
              </div>
              <div className="bg-blue-50 p-4 rounded-lg flex flex-col justify-center items-center text-center">
                <p className="text-sm text-gray-600 mb-1">Transaktionen gesamt</p>
                <p className="text-2xl font-bold text-blue-700">{customer.totalTransactions}</p>
              </div>
              <div className="bg-yellow-50 p-4 rounded-lg flex flex-col justify-center items-center text-center">
                <p className="text-sm text-gray-600 mb-1">Einsteiger</p>
                <div className="flex items-center mt-2">
                  <AwardIcon className="h-10 w-10 text-yellow-700 mr-2" /> {/* Replaced img with AwardIcon */}
                  <p className="text-2xl font-bold text-yellow-700">Level 1</p>
                </div>
              </div>
            </div>
          </Card>

          {/* Ausbildungsfortschritt */}
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Ausbildungsfortschritt</h2>
            <div className="space-y-6">
              {customer.trainingProgress.map((section) => (
                <div
                  key={section.id}
                  className={`p-4 rounded-lg border
                    ${section.status === 'Aktuell' ? 'bg-purple-50 border-purple-200' :
                      section.status === 'Abgeschlossen' ? 'bg-green-50 border-green-200' :
                      'bg-gray-50 border-gray-200'}`}
                >
                  <div className="flex items-center justify-between mb-2">
                    <h3 className="text-lg font-medium text-gray-900 flex items-center">
                      <AwardIcon className="h-6 w-6 text-gray-500 mr-2" /> {/* Changed to AwardIcon */}
                      {section.id}. {section.name}
                    </h3>
                    <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${getStatusClasses(section.status)}`}>
                      {section.status}
                    </span>
                  </div>
                  <p className="text-sm text-gray-600 mb-3">
                    Fortschritt: {section.completedHours} / {section.requiredHours} Mantrailing-Stunden
                  </p>
                  <div className="flex flex-wrap gap-2">
                    {Array.from({ length: section.requiredHours }).map((_, i) => (
                      <TrainingPawIcon key={i} filled={i < section.completedHours} />
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </Card>
        </div>

        {/* Right Column */}
        <div className="lg:col-span-1 space-y-6">
          {/* Konto-Übersicht (Detailed) */}
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Konto-Übersicht</h2>
            <div className="space-y-2 text-gray-700">
              <div className="flex justify-between">
                <span>Guthaben</span>
                <span className="font-semibold">{customer.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</span>
              </div>
              <div className="flex justify-between">
                <span>Transaktionen</span>
                <span className="font-semibold">{customer.totalTransactions}</span>
              </div>
              <div className="flex justify-between">
                <span>Erstellt am</span>
                <span className="font-semibold">{customer.createdAt}</span>
              </div>
              <div className="flex justify-between">
                <span>Erstellt von</span>
                <span className="font-semibold">{customer.createdBy}</span>
              </div>
            </div>
          </Card>

          {/* QR-Code */}
          <Card className="text-center">
            <h2 className="text-xl font-semibold text-gray-900 mb-4">QR-Code</h2>
            <QRCodeDisplay dataUrl={customer.qrCodeData} className="mb-3" />
            <p className="text-sm text-gray-600">
              Scannen, um diese Kundenkarte schnell aufzurufen.
            </p>
          </Card>

          {/* Dokumentenverwaltung */}
          <Card>
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-xl font-semibold text-gray-900">Dokumentenverwaltung</h2>
              <Button variant="ghost" icon={UploadIcon} size="sm"> {/* Changed to UploadIcon */}
                Hochladen
              </Button>
            </div>
            {customer.documents.length === 0 ? (
              <p className="text-gray-500 text-sm">Keine Dokumente vorhanden.</p>
            ) : (
              <ul className="space-y-2">
                {customer.documents.map((doc) => (
                  <li key={doc.id} className="flex justify-between items-center text-gray-700 text-sm">
                    <span>{doc.name}</span>
                    <a href={doc.url} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:underline">
                      Anzeigen
                    </a>
                  </li>
                ))}
              </ul>
            )}
          </Card>
        </div>
      </div>

      <TransactionConfirmationModal
        isOpen={showModal}
        onClose={() => setShowModal(false)}
        onConfirm={handleConfirmTransaction}
        data={transactionData}
      />
    </div>
  );
};

export default CustomerDetails;

