const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>(INITIAL_MOCK_CUSTOMERS);
  const [transactions, setTransactions] = useState<Transaction[]>(INITIAL_MOCK_TRANSACTIONS);
  const [users, setUsers] = useState<User[]>(INITIAL_MOCK_USERS); // New state for users

  const handleUpdateCustomer = (updatedCustomer: Customer) => {
    setCustomers(prevCustomers =>
      prevCustomers.map(c => (c.id === updatedCustomer.id ? updatedCustomer : c))
    );
  };

  const handleAddTransaction = (newTransaction: Transaction) => {
    setTransactions(prevTransactions => [...prevTransactions, newTransaction]);
  };

  // User management functions
  const handleAddUser = (newUser: User) => {
    setUsers(prevUsers => [...prevUsers, newUser]);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(prevUsers =>
      prevUsers.map(u => (u.id === updatedUser.id ? updatedUser : u))
    );
  };

  const handleDeleteUser = (userId: string) => {
    setUsers(prevUsers => prevUsers.filter(u => u.id !== userId));
  };


  return (
    <div className="flex min-h-screen bg-gray-100">
      <Sidebar appName="Mantrailing Card" />
      <main className="flex-1 md:ml-64 p-0"> {/* Adjusted margin for sidebar */}
        <Routes>
          <Route path="/" element={<Dashboard customers={customers} transactions={transactions} />} />
          <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} />} />
          <Route
            path="/customers/:id"
            element={
              <CustomerDetails
                customers={customers}
                transactions={transactions}
                onUpdateCustomer={handleUpdateCustomer}
                onAddTransaction={handleAddTransaction}
              />
            }
          />
          <Route path="/reports" element={<Reports customers={customers} transactions={transactions} />} />
          {/* Add more routes as needed, e.g., /users */}
          <Route
            path="/users"
            element={
              <UserManagement
                users={users}
                onAddUser={handleAddUser}
                onUpdateUser={handleUpdateUser}
                onDeleteUser={handleDeleteUser}
              />
            }
          />
        </Routes>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import Card from '../components/Card';
import StatCard from '../components/StatCard';
import { REFERENCE_DATE } from '../constants'; // Only REFERENCE_DATE remains in constants
import Avatar from '../components/Avatar';
import { ArrowUpCircleIcon, ArrowDownCircleIcon, UsersIcon, DollarSignIcon, ClipboardIcon, RepeatIcon } from '../components/Icons';
import { Link } from 'react-router-dom';
import { parseDateString, isSameDay, isSameMonth } from '../utils';
import { Customer, Transaction } from '../types'; // Import types

interface DashboardProps {
  customers: Customer[];
  transactions: Transaction[];
}

const Dashboard: React.FC<DashboardProps> = ({ customers, transactions }) => {
  // Dynamic calculations for Dashboard Stats
  const totalCustomers = customers.length;
  const totalBalance = customers.reduce((sum, customer) => sum + customer.balance, 0);

  const today = REFERENCE_DATE;
  const currentMonthTransactions = transactions.filter(t => {
    const transactionDate = parseDateString(t.date);
    return transactionDate && isSameMonth(transactionDate, today);
  });
  const todayTransactions = transactions.filter(t => {
    const transactionDate = parseDateString(t.date);
    return transactionDate && isSameDay(transactionDate, today);
  });

  const dashboardStats = [
    { title: 'Kunden Gesamt', value: totalCustomers, icon: UsersIcon, color: 'bg-green-100 text-green-700' },
    { title: 'Guthaben gesamt', value: totalBalance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' }), icon: DollarSignIcon, color: 'bg-orange-100 text-orange-700' },
    { title: 'Transaktionen Heute', value: todayTransactions.length, icon: ClipboardIcon, color: 'bg-blue-100 text-blue-700' },
    { title: 'Transaktionen Monat', value: currentMonthTransactions.length, icon: RepeatIcon, color: 'bg-purple-100 text-purple-700' },
  ];

  // Aktuelle Kunden (based on createdAt, max 5, scrollable)
  const recentCustomers = [...customers]
    .sort((a, b) => {
      const dateA = parseDateString(a.createdAt);
      const dateB = parseDateString(b.createdAt);
      if (!dateA || !dateB) return 0; // Handle invalid dates
      return dateB.getTime() - dateA.getTime(); // Sort descending
    })
    .slice(0, 5); // Take top 5

  // Letzte Transaktionen (max 5, scrollable)
  const latestTransactions = [...transactions]
    .sort((a, b) => {
      const dateA = parseDateString(a.date);
      const dateB = parseDateString(b.date);
      if (!dateA || !dateB) return 0; // Handle invalid dates
      return dateB.getTime() - dateA.getTime(); // Sort descending
    })
    .slice(0, 5); // Take top 5

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <h1 className="text-3xl font-bold text-gray-900 mb-2">Willkommen, Christian Christian!</h1>
      <p className="text-gray-600 mb-8">Übersicht ihrer Mantrailing-Wertkarten</p>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {dashboardStats.map((stat, index) => (
          <StatCard
            key={index}
            title={stat.title}
            value={stat.value}
            icon={stat.icon}
            color={stat.color}
          />
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Aktuelle Kunden */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Aktuelle Kunden</h2>
          <div className="space-y-4 max-h-72 overflow-y-auto custom-scrollbar"> {/* Added max-h and overflow for scroll */}
            {recentCustomers.length === 0 ? (
              <p className="text-gray-500 text-sm">Keine aktuellen Kunden gefunden.</p>
            ) : (
              recentCustomers.map((customer) => (
                <Link to={`/customers/${customer.id}`} key={customer.id} className="flex items-center justify-between p-3 bg-gray-50 hover:bg-gray-100 rounded-lg transition-colors duration-200">
                  <div className="flex items-center">
                    <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="md" className="mr-3" />
                    <div>
                      <p className="font-medium text-gray-900">{customer.firstName} {customer.lastName}</p>
                      <p className="text-sm text-gray-500">{customer.dogName}</p>
                    </div>
                  </div>
                  <p className="font-semibold text-gray-800">{customer.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</p>
                </Link>
              ))
            )}
          </div>
        </Card>

        {/* Letzte Transaktionen */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Letzte Transaktionen</h2>
          <div className="space-y-4 max-h-72 overflow-y-auto custom-scrollbar"> {/* Added max-h and overflow for scroll */}
            {latestTransactions.length === 0 ? (
              <p className="text-gray-500 text-sm">Keine aktuellen Transaktionen gefunden.</p>
            ) : (
              latestTransactions.map((transaction) => {
                const customer = customers.find(c => c.id === transaction.customerId);
                const isRecharge = transaction.type === 'recharge';
                const TransactionIcon = isRecharge ? ArrowUpCircleIcon : ArrowDownCircleIcon;
                const iconColor = isRecharge ? 'text-green-500' : 'text-red-500';
                const amountColor = isRecharge ? 'text-green-700' : 'text-red-700';
                const amountSign = isRecharge ? '+' : '-'; // Changed to dynamically show + or -

                return (
                  <div key={transaction.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div className="flex items-center">
                      <span className={`p-2 rounded-full bg-gray-200 mr-3 ${iconColor}`}>
                        <TransactionIcon className="h-5 w-5" />
                      </span>
                      <div>
                        <p className="font-medium text-gray-900">{customer?.firstName} {customer?.lastName}</p>
                        <p className="text-sm text-gray-500">{transaction.date} - {transaction.description}</p>
                      </div>
                    </div>
                    <p className={`font-semibold ${amountColor}`}>
                      {amountSign}{Math.abs(transaction.amount).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                    </p>
                  </div>
                );
              })
            )}
          </div>
        </Card>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import Card from '../components/Card';
import StatCard from '../components/StatCard';
import Table, { Column } from '../components/Table';
import Button from '../components/Button';
import Avatar from '../components/Avatar';
import { PlusIcon, ChevronRightIcon, UsersIcon, HeartIcon, ClipboardIcon, RepeatIcon, UserPlusIcon } from '../components/Icons';
import { ALPHABET, REFERENCE_DATE } from '../constants'; // Only ALPHABET and REFERENCE_DATE remain in constants
import { Customer, CustomerTableData, TrainingLevelEnum, Transaction } from '../types'; // Import types
import { useNavigate } from 'react-router-dom';
import { parseDateString, isSameMonth } from '../utils';

interface CustomerManagementProps {
  customers: Customer[];
  transactions: Transaction[];
}

const CustomerManagement: React.FC<CustomerManagementProps> = ({ customers, transactions }) => {
  const navigate = useNavigate();
  const [activeFilter, setActiveFilter] = useState<string>('Alle');

  // Dynamic calculations for Customer Management Stats
  const totalCustomers = customers.length;
  const totalBalance = customers.reduce((sum, c) => sum + c.balance, 0);

  const today = REFERENCE_DATE;
  const currentMonthTransactions = transactions.filter(t => {
    const transactionDate = parseDateString(t.date);
    return transactionDate && isSameMonth(transactionDate, today);
  });
  const monthlyTransactionsCount = currentMonthTransactions.length;

  // Determine active customers (those with transactions in the current month)
  const activeCustomerIds = new Set(
    currentMonthTransactions.map(t => t.customerId)
  );
  const activeCustomersCount = customers.filter(c => activeCustomerIds.has(c.id)).length;


  const filteredCustomers = customers.filter((customer) => {
    if (activeFilter === 'Alle') {
      return true;
    }
    return customer.lastName.startsWith(activeFilter);
  });

  const customerTableData: CustomerTableData[] = filteredCustomers.map((customer) => ({
    id: customer.id,
    avatarInitials: customer.avatarInitials,
    avatarColor: customer.avatarColor,
    name: `${customer.firstName} ${customer.lastName}\n${customer.id}`,
    dog: customer.dogName,
    balance: customer.balance,
    level: customer.level,
    createdAt: customer.createdAt,
  }));

  const columns: Column<CustomerTableData>[] = [
    {
      key: 'name',
      header: 'Kunde',
      render: (item: CustomerTableData) => (
        <div className="flex items-center">
          <Avatar initials={item.avatarInitials} color={item.avatarColor} size="md" className="mr-3" />
          <div>
            <p className="font-medium text-gray-900">{item.name.split('\n')[0]}</p>
            <p className="text-sm text-gray-500">{item.name.split('\n')[1]}</p>
          </div>
        </div>
      ),
    },
    { key: 'dog', header: 'Hund' },
    {
      key: 'balance',
      header: 'Guthaben',
      render: (item: CustomerTableData) => item.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' }),
    },
    {
      key: 'level',
      header: 'Level',
      render: (item: CustomerTableData) => (
        <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800">
          {item.level}
        </span>
      ),
    },
    { key: 'createdAt', header: 'Erstellt' },
    {
      key: 'id',
      header: '',
      render: (item: CustomerTableData) => (
        <ChevronRightIcon className="h-5 w-5 text-gray-400" />
      ),
      className: 'text-right',
    },
  ];

  const handleRowClick = (customerData: CustomerTableData) => {
    navigate(`/customers/${customerData.id}`);
  };

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <div className="flex justify-between items-center mb-2">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Kundenverwaltung</h1>
          <p className="text-gray-600">Verwalten Sie alle Ihre Kunden an einem Ort</p>
        </div>
        <Button variant="success" icon={UserPlusIcon}>
          Neuer Kunde
        </Button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 my-8">
        <StatCard
          title="Kunden Gesamt"
          value={totalCustomers}
          icon={UsersIcon}
          color="bg-green-100 text-green-700"
        />
        <StatCard
          title="Aktiv"
          value={activeCustomersCount} // Dynamically calculated
          icon={HeartIcon}
          color="bg-orange-100 text-orange-700"
        />
        <StatCard
          title="Guthaben"
          value={totalBalance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })} // Dynamically calculated
          icon={ClipboardIcon}
          color="bg-blue-100 text-blue-700"
        />
        <StatCard
          title="Transaktionen Monat"
          value={monthlyTransactionsCount} // Dynamically calculated
          icon={RepeatIcon}
          color="bg-purple-100 text-purple-700"
        />
      </div>

      {/* Alphabet Filter */}
      <Card className="mb-6 px-4 py-2">
        <div className="flex flex-wrap justify-between gap-2">
          <button
            onClick={() => setActiveFilter('Alle')}
            className={`px-3 py-1.5 rounded-md text-sm font-medium transition-colors
              ${activeFilter === 'Alle' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
          >
            Alle
          </button>
          {ALPHABET.map((letter) => (
            <button
              key={letter}
              onClick={() => setActiveFilter(letter)}
              className={`px-3 py-1.5 rounded-md text-sm font-medium transition-colors
                ${activeFilter === letter ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
            >
              {letter}
            </button>
          ))}
        </div>
      </Card>

      {/* Customer List Table */}
      <Card>
        <h2 className="text-xl font-semibold text-gray-900 mb-4">Kundenliste ({filteredCustomers.length})</h2>
        <Table data={customerTableData} columns={columns} onRowClick={handleRowClick} />
      </Card>
    </div>
  );
};

export default CustomerManagement;

