import QRCodeDisplay from '../components/QRCodeDisplay';
import TransactionConfirmationModal from '../components/TransactionConfirmationModal';
import TransactionTypeSelectionModal from '../components/TransactionTypeSelectionModal'; // Import new modal
import {
  ArrowLeftIcon,
  HeartIcon,
  CreditCardIcon,
  MailIcon,
  PhoneIcon,
  AwardIcon,
  UploadIcon,
  UserIcon,
  PawPrintIcon,
  ChevronDownIcon, // Import ChevronDownIcon
} from '../components/Icons';
import { CURRENT_EMPLOYEE, REFERENCE_DATE } from '../constants'; // Only CURRENT_EMPLOYEE and REFERENCE_DATE remain
import { Customer, TrainingLevelEnum, TransactionConfirmationData, Transaction } from '../types';

interface TrainingHourCircleProps {
  filled: boolean;
  className?: string;
}

const TrainingPawIcon: React.FC<TrainingHourCircleProps> = ({ filled, className = '' }) => (
  // Updated to use PawPrintIcon inside a circle for both filled and unfilled states
  <div
    className={`flex items-center justify-center h-8 w-8 rounded-full border
      ${filled ? 'bg-gray-100 border-gray-300' : 'bg-gray-50 border-gray-200'}
      ${className}`}
  >
    <PawPrintIcon className={`h-5 w-5 ${filled ? 'text-blue-500' : 'text-gray-400'}`} />
  </div>
);

interface CustomerDetailsProps {
  customers: Customer[];
  transactions: Transaction[];
  onUpdateCustomer: (updatedCustomer: Customer) => void;
  onAddTransaction: (newTransaction: Transaction) => void;
}

const CustomerDetails: React.FC<CustomerDetailsProps> = ({
  customers,
  transactions,
  onUpdateCustomer,
  onAddTransaction,
}) => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const [showConfirmationModal, setShowConfirmationModal] = useState(false); // Renamed for clarity
  const [showTransactionTypeModal, setShowTransactionTypeModal] = useState(false); // New state for selection modal
  const [transactionData, setTransactionData] = useState<TransactionConfirmationData | null>(null);
  // State to manage expanded/collapsed sections
  const [expandedSections, setExpandedSections] = useState<Record<number, boolean>>(() => {
    // Initialize all sections as collapsed by default
    const initialState: Record<number, boolean> = {};
    customers.find((c) => c.id === id)?.trainingProgress.forEach(section => {
      initialState[section.id] = false;
    });
    return initialState;
  });

  const customer = customers.find((c) => c.id === id); // Get customer from props

  if (!customer) {
    return (
      <div className="p-8 text-center text-red-600">
        Kunde mit ID "{id}" nicht gefunden.
        <Button variant="primary" onClick={() => navigate('/customers')} className="mt-4">
          Zurück zur Kundenliste
        </Button>
      </div>
    );
  }

  // This function now specifically opens the *confirmation* modal
  const handleOpenConfirmationModal = (amount: number, type: 'Aufladung' | 'Abbuchung', description?: string) => {
    const oldBalance = customer.balance;
    const newBalance = type === 'Aufladung' ? oldBalance + amount : oldBalance - amount;
    setTransactionData({
      customerId: customer.id,
      customerName: `${customer.firstName} ${customer.lastName}`,
      employee: CURRENT_EMPLOYEE,
      transactionType: type,
      amount: amount,
      oldBalance: oldBalance,
      newBalance: newBalance,
      description: description, // Pass the description
    });
    setShowConfirmationModal(true);
  };

  const handleConfirmTransaction = () => {
    if (!transactionData || !customer) return;

    // Update customer's balance and totalTransactions
    const updatedCustomer: Customer = {
      ...customer,
      balance: transactionData.newBalance,
      totalTransactions: customer.totalTransactions + 1,
    };
    onUpdateCustomer(updatedCustomer); // Propagate update to global state

    // Create and add new transaction
    const newTransaction: Transaction = {
      id: `trx-${transactions.length + 1}-${Date.now()}`, // Simple unique ID
      customerId: customer.id,
      type: transactionData.transactionType === 'Aufladung' ? 'recharge' : 'debit',
      description: transactionData.description || (transactionData.transactionType === 'Aufladung' ? 'Aufladung' : 'Abbuchung'),
      amount: transactionData.amount,
      date: REFERENCE_DATE.toLocaleDateString('de-DE'), // Use REFERENCE_DATE for consistency
      employee: CURRENT_EMPLOYEE,
    };
    onAddTransaction(newTransaction); // Propagate new transaction to global state

    console.log('Transaction confirmed:', transactionData);
    setShowConfirmationModal(false);
    setTransactionData(null);
  };

  // New handler for selecting transaction type from the selection modal
  const handleSelectTransactionType = (type: 'Aufladung' | 'Abbuchung') => {
    setShowTransactionTypeModal(false); // Close the selection modal

    let defaultAmount = 0;
    let description = '';
    if (type === 'Aufladung') {
      defaultAmount = 215; // Example default amount for recharge
      description = 'Guthabenaufladung';
    } else { // Abbuchung
      defaultAmount = 18; // Example default amount for debit
      description = 'Mantrailing-Stunde';
    }
    handleOpenConfirmationModal(defaultAmount, type, description); // Open the confirmation modal
  };

  const getStatusClasses = (status: string) => {
    switch (status) {
      case 'Aktuell':
        return 'bg-green-100 text-green-800';
      case 'Gesperrt':
        return 'bg-red-100 text-red-800';
      case 'Abgeschlossen':
        return 'bg-blue-100 text-blue-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  // Helper component for a consistent data row
  const DataRow: React.FC<{ Icon: React.ElementType; label: string; value: string | number }> = ({ Icon, label, value }) => (
    <div>
      <div className="flex items-center text-gray-500 mb-1">
        <Icon className="h-4 w-4 mr-2" />
        <span className="text-sm font-medium">{label}</span>
      </div>
      <p className="font-semibold text-gray-900 ml-6">{value}</p> {/* Adjusted margin for alignment */}
    </div>
  );

  const toggleSection = (sectionId: number) => {
    setExpandedSections(prev => ({
      ...prev,
      [sectionId]: !prev[sectionId],
    }));
  };


  return (
    <div className="p-6 md:p-8 lg:p-10 min-h-screen">
      <div className="flex items-center justify-between mb-6 flex-wrap gap-4">
        <div className="flex items-center">
          <button onClick={() => navigate('/customers')} className="text-gray-500 hover:text-gray-700 mr-4">
            <ArrowLeftIcon className="h-6 w-6" />
          </button>
          <h1 className="text-2xl font-bold text-gray-900 flex items-center">
            {customer.firstName} {customer.lastName}
            <span className="text-gray-500 font-normal text-base ml-2">Kundendetails & Übersicht</span>
          </h1>
        </div>
        <div className="flex space-x-3">
          <Button variant="outline">Stammdaten</Button>
          <Button variant="success" onClick={() => setShowTransactionTypeModal(true)}>
            Transaktionen
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column */}
        <div className="lg:col-span-2 space-y-6">
          {/* Persönliche Daten */}
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Persönliche Daten</h2>
            <div className="flex items-start"> {/* Use flex to align avatar and data grid */}
              <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="lg" className="mr-6 flex-shrink-0" />
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-12 gap-y-6 flex-grow"> {/* Two-column grid for data */}
                <DataRow Icon={UserIcon} label="Vorname" value={customer.firstName} />
                <DataRow Icon={UserIcon} label="Nachname" value={customer.lastName} />
                <DataRow Icon={MailIcon} label="E-Mail" value={customer.email} />
                <DataRow Icon={PhoneIcon} label="Telefon" value={customer.phone} />
                <DataRow Icon={HeartIcon} label="Hund" value={customer.dogName} />
                <DataRow Icon={CreditCardIcon} label="Chipnummer" value={customer.chipNumber} />
              </div>
            </div>
          </Card>

          {/* Konto-Übersicht (Summary Cards) */}
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Konto-Übersicht</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="bg-green-50 p-4 rounded-lg flex flex-col justify-center items-center text-center">
                <p className="text-sm text-gray-600 mb-1">Aktuelles Guthaben</p>
                <p className="text-2xl font-bold text-green-700">{customer.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</p>
              </div>
              <div className="bg-blue-50 p-4 rounded-lg flex flex-col justify-center items-center text-center">
                <p className="text-sm text-gray-600 mb-1">Transaktionen gesamt</p>
                <p className="text-2xl font-bold text-blue-700">{customer.totalTransactions}</p>
              </div>
              <div className="bg-yellow-50 p-4 rounded-lg flex flex-col justify-center items-center text-center">
                <p className="text-sm text-gray-600 mb-1">Einsteiger</p>
                <div className="flex items-center mt-2">
                  <AwardIcon className="h-10 w-10 text-yellow-700 mr-2" />
                  <p className="text-2xl font-bold text-yellow-700">Level 1</p>
                </div>
              </div>
            </div>
          </Card>

          {/* Ausbildungsfortschritt */}
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Ausbildungsfortschritt</h2>
            <div className="space-y-6">
              {customer.trainingProgress.map((section) => {
                let sectionBgClass = 'bg-gray-50 border-gray-200';
                let levelCircleBgClass = 'bg-gray-400';

                if (section.status === 'Aktuell') {
                  sectionBgClass = 'bg-pink-50 border-pink-200';
                } else if (section.status === 'Gesperrt') {
                  sectionBgClass = 'bg-green-50 border-green-200';
                } else if (section.status === 'Abgeschlossen') {
                  sectionBgClass = 'bg-blue-50 border-blue-200';
                }

                if (section.id === 1) {
                  levelCircleBgClass = 'bg-pink-500';
                } else if (section.id === 2) {
                  levelCircleBgClass = 'bg-green-500';
                }

                const isExpanded = expandedSections[section.id];

                return (
                  <div key={section.id} className={`p-4 rounded-lg border ${sectionBgClass}`}>
                    <button
                      className="flex items-center justify-between w-full text-left"
                      onClick={() => toggleSection(section.id)}
                      aria-expanded={isExpanded}
                      aria-controls={`section-content-${section.id}`}
                    >
                      <h3 className="text-lg font-medium text-gray-900 flex items-center">
                        <span className={`flex items-center justify-center h-8 w-8 rounded-full text-white font-bold text-base mr-3 ${levelCircleBgClass}`}>
                          {section.id}
                        </span>
                        {section.name}
                      </h3>
                      <div className="flex items-center">
                        <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${getStatusClasses(section.status)} mr-2`}>
                          {section.status}
                        </span>
                        <ChevronDownIcon className={`h-5 w-5 text-gray-500 transition-transform duration-200 ${isExpanded ? 'rotate-180' : ''}`} />
                      </div>
                    </button>

                    <div id={`section-content-${section.id}`} className={`${isExpanded ? 'block' : 'hidden'} mt-3`}>
                      <p className="text-sm text-gray-600 mb-3 ml-11">
                        Fortschritt: {section.completedHours} / {section.requiredHours} Mantrailing-Stunden
                      </p>
                      <div className="flex flex-wrap gap-2 ml-11">
                        {Array.from({ length: section.requiredHours }).map((_, i) => (
                          <TrainingPawIcon key={i} filled={i < section.completedHours} />
                        ))}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </Card>
        </div>

        {/* Right Column */}
        <div className="lg:col-span-1 space-y-6">
          {/* Konto-Übersicht (Detailed) */}
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Konto-Übersicht</h2>
            <div className="space-y-2 text-gray-700">
              <div className="flex justify-between">
                <span>Guthaben</span>
                <span className="font-semibold">{customer.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</span>
              </div>
              <div className="flex justify-between">
                <span>Transaktionen</span>
                <span className="font-semibold">{customer.totalTransactions}</span>
              </div>
              <div className="flex justify-between">
                <span>Erstellt am</span>
                <span className="font-semibold">{customer.createdAt}</span>
              </div>
              <div className="flex justify-between">
                <span>Erstellt von</span>
                <span className="font-semibold">{customer.createdBy}</span>
              </div>
            </div>
          </Card>

          {/* QR-Code */}
          <Card className="text-center">
            <h2 className="text-xl font-semibold text-gray-900 mb-4">QR-Code</h2>
            <QRCodeDisplay dataUrl={customer.qrCodeData} className="mb-3" />
            <p className="text-sm text-gray-600">
              Scannen, um diese Kundenkarte schnell aufzurufen.
            </p>
          </Card>

          {/* Dokumentenverwaltung */}
          <Card>
            <div className="flex justify-between items-center mb-4">
              <h2 className="text-xl font-semibold text-gray-900">Dokumentenverwaltung</h2>
              <Button variant="ghost" icon={UploadIcon} size="sm">
                Hochladen
              </Button>
            </div>
            {customer.documents.length === 0 ? (
              <p className="text-gray-500 text-sm">Keine Dokumente vorhanden.</p>
            ) : (
              <ul className="space-y-2">
                {customer.documents.map((doc) => (
                  <li key={doc.id} className="flex justify-between items-center text-gray-700 text-sm">
                    <span>{doc.name}</span>
                    <a href={doc.url} target="_blank" rel="noopener noreferrer" className="text-blue-600 hover:underline">
                      Anzeigen
                    </a>
                  </li>
                ))}
              </ul>
            )}
          </Card>
        </div>
      </div>

      <TransactionConfirmationModal
        isOpen={showConfirmationModal} // Use the new state
        onClose={() => setShowConfirmationModal(false)}
        onConfirm={handleConfirmTransaction}
        data={transactionData}
      />

      <TransactionTypeSelectionModal
        isOpen={showTransactionTypeModal}
        onClose={() => setShowTransactionTypeModal(false)}
        onSelectType={handleSelectTransactionType}
      />
    </div>
  );
};

export default CustomerDetails;

import React, { useState } from 'react';
import Card from '../components/Card';
import StatCard from '../components/StatCard';
import Button from '../components/Button';
import Select from '../components/Select';
import Avatar from '../components/Avatar';
import { MOCK_REPORT_TYPES, MOCK_REPORT_PERIODS, MOCK_REPORT_EMPLOYEES, REFERENCE_DATE } from '../constants'; // MOCK_TRANSACTIONS and MOCK_CUSTOMERS removed
import { ArrowUpCircleIcon, ArrowDownCircleIcon, DollarSignIcon, ClipboardIcon, UsersIcon } from '../components/Icons';
import { parseDateString, isSameMonth } from '../utils';
import { Customer, Transaction } from '../types'; // Import types

interface ReportsProps {
  customers: Customer[];
  transactions: Transaction[];
}

const Reports: React.FC<ReportsProps> = ({ customers, transactions }) => {
  const [reportType, setReportType] = useState('Monatlich');
  // Initialize timePeriod to match the month of REFERENCE_DATE for consistency
  const defaultPeriodMonth = REFERENCE_DATE.toLocaleString('de-DE', { month: 'long' });
  const defaultPeriodYear = REFERENCE_DATE.getFullYear();
  const defaultTimePeriod = `${defaultPeriodMonth.charAt(0).toUpperCase() + defaultPeriodMonth.slice(1)} ${defaultPeriodYear}`;

  const [timePeriod, setTimePeriod] = useState(defaultTimePeriod);
  const [employee, setEmployee] = useState('Alle Mitarbeiter');

  // Helper for parsing current filter period
  const getFilterPeriodDate = () => {
    if (timePeriod === 'Gesamt') return null;
    // Assuming timePeriod is in "Month YYYY" format for detailed filtering
    // For consistency with mock data, let's treat "Dezember 2025" as the REFERENCE_DATE's month
    const [monthName, year] = timePeriod.split(' ');
    // Simple mapping for German months to numbers (0-indexed)
    const monthMap: { [key: string]: number } = {
      'Januar': 0, 'Februar': 1, 'März': 2, 'April': 3, 'Mai': 4, 'Juni': 5,
      'Juli': 6, 'August': 7, 'September': 8, 'Oktober': 9, 'November': 10, 'Dezember': 11
    };
    const monthIndex = monthMap[monthName];
    if (monthIndex !== undefined && year) {
      return new Date(parseInt(year, 10), monthIndex, 1);
    }
    return null;
  };

  const selectedFilterPeriod = getFilterPeriodDate();

  // Filter transactions based on selected criteria
  const filteredTransactions = transactions.filter(t => { // Use transactions prop
    const transactionDate = parseDateString(t.date);
    if (!transactionDate) return false;

    // Filter by period
    let matchesPeriod = true;
    if (timePeriod === 'Gesamt') {
      matchesPeriod = true;
    } else if (selectedFilterPeriod) {
      matchesPeriod = isSameMonth(transactionDate, selectedFilterPeriod);
    }

    // Filter by employee
    const matchesEmployee = employee === 'Alle Mitarbeiter' || t.employee === employee;

    return matchesPeriod && matchesEmployee;
  });

  // Dynamic calculations for Report Stats
  const monthlyRecharges = filteredTransactions
    .filter(t => t.type === 'recharge')
    .reduce((sum, t) => sum + Math.abs(t.amount), 0);

  const monthlyDebits = filteredTransactions
    .filter(t => t.type === 'debit')
    .reduce((sum, t) => sum + Math.abs(t.amount), 0);

  const totalMonthlyTransactions = filteredTransactions.length;

  const activeCustomerIdsInPeriod = new Set(
    filteredTransactions.map(t => t.customerId)
  );
  const activeCustomersInPeriodCount = customers.filter(c => activeCustomerIdsInPeriod.has(c.id)).length; // Use customers prop


  const getTopCustomers = () => {
    const customerTransactions: { [key: string]: { count: number; totalAmount: number } } = {};
    filteredTransactions.forEach(t => {
      if (!customerTransactions[t.customerId]) {
        customerTransactions[t.customerId] = { count: 0, totalAmount: 0 };
      }
      customerTransactions[t.customerId].count++;
      customerTransactions[t.customerId].totalAmount += Math.abs(t.amount); // Consider total value
    });

    return Object.entries(customerTransactions)
      .sort(([, a], [, b]) => b.totalAmount - a.totalAmount) // Sort by total amount spent
      .slice(0, 3) // Get top 3
      .map(([customerId, data]) => {
        const customer = customers.find(c => c.id === customerId); // Use customers prop
        return {
          customerName: customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt',
          dogName: customer?.dogName || '',
          transactionCount: data.count,
          totalAmount: data.totalAmount,
          avatarInitials: customer?.avatarInitials || '?',
          avatarColor: customer?.avatarColor || 'bg-gray-400',
          id: customerId,
        };
      });
  };

  const topCustomers = getTopCustomers();

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <h1 className="text-3xl font-bold text-gray-900 mb-2">Berichte & Statistiken</h1>
      <p className="text-gray-600 mb-8">Analysieren und exportieren Sie Ihre Geschäftsdaten</p>

      {/* Filters and Export Buttons */}
      <Card className="mb-8">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 items-end">
          <Select
            id="reportType"
            label="Berichtstyp"
            options={MOCK_REPORT_TYPES.map(type => ({ value: type, label: type }))}
            value={reportType}
            onChange={(e) => setReportType(e.target.value)}
          />
          <Select
            id="timePeriod"
            label="Zeitraum"
            options={MOCK_REPORT_PERIODS.map(period => ({ value: period, label: period }))}
            value={timePeriod}
            onChange={(e) => setTimePeriod(e.target.value)}
          />
          <Select
            id="employee"
            label="Mitarbeiter"
            options={MOCK_REPORT_EMPLOYEES.map(emp => ({ value: emp, label: emp }))}
            value={employee}
            onChange={(e) => setEmployee(e.target.value)}
          />
          <Button variant="outline" className="w-full lg:w-auto">
            Als CSV exportieren
          </Button>
          <Button variant="success" className="w-full lg:w-auto">
            Als PDF exportieren
          </Button>
        </div>
      </Card>

      {/* Stats Cards for Reports */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <StatCard
          title="Gesamtaufladungen (Monat)"
          value={monthlyRecharges.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
          icon={UsersIcon}
          color="bg-green-100 text-green-700"
        />
        <StatCard
          title="Abbuchungen (Monat)"
          value={monthlyDebits.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
          icon={DollarSignIcon}
          color="bg-orange-100 text-orange-700"
        />
        <StatCard
          title="Transaktionen"
          value={totalMonthlyTransactions}
          icon={ClipboardIcon}
          color="bg-blue-100 text-blue-700"
        />
        <StatCard
          title="Aktive Kunden"
          value={activeCustomersInPeriodCount}
          icon={UsersIcon}
          color="bg-purple-100 text-purple-700"
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Transaktionen im Zeitraum */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Transaktionen im Zeitraum ({filteredTransactions.length})</h2>
          <div className="space-y-4 max-h-96 overflow-y-auto custom-scrollbar"> {/* Added max-h and overflow for scroll */}
            {filteredTransactions.length === 0 ? (
              <p className="text-gray-500">Keine Transaktionen für den ausgewählten Zeitraum und Mitarbeiter gefunden.</p>
            ) : (
              filteredTransactions.map((transaction) => {
                const customer = customers.find(c => c.id === transaction.customerId); // Use customers prop
                const isRecharge = transaction.type === 'recharge';
                const TransactionIcon = isRecharge ? ArrowUpCircleIcon : ArrowDownCircleIcon;
                const iconColor = isRecharge ? 'text-green-500' : 'text-red-500';
                const amountColor = isRecharge ? 'text-green-700' : 'text-red-700';
                const amountSign = isRecharge ? '+' : '-';

                return (
                  <div key={transaction.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div className="flex items-center">
                      <span className={`p-2 rounded-full bg-gray-200 mr-3 ${iconColor}`}>
                        <TransactionIcon className="h-5 w-5" />
                      </span>
                      <div>
                        <p className="font-medium text-gray-900">{transaction.description}</p>
                        <p className="text-sm text-gray-500">
                          {transaction.date} von {transaction.employee}
                          {customer && ` für ${customer.firstName} ${customer.lastName}`}
                        </p>
                      </div>
                    </div>
                    <p className={`font-semibold ${amountColor}`}>
                      {amountSign}{Math.abs(transaction.amount).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                    </p>
                  </div>
                );
              })
            )}
          </div>
        </Card>

        {/* Top Kunden im Zeitraum */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Top Kunden im Zeitraum</h2>
          <div className="space-y-4 max-h-96 overflow-y-auto custom-scrollbar"> {/* Added max-h and overflow for scroll */}
            {topCustomers.length === 0 ? (
              <p className="text-gray-500">Keine Top-Kunden für den ausgewählten Zeitraum und Mitarbeiter gefunden.</p>
            ) : (
              topCustomers.map((customer, index) => (
                <div key={customer.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <div className="flex items-center">
                    <span className="text-lg font-bold text-gray-700 mr-3">{index + 1}.</span>
                    <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="md" className="mr-3" />
                    <div>
                      <p className="font-medium text-gray-900">{customer.customerName}</p>
                      <p className="text-sm text-gray-500">
                        {customer.dogName} &bull; {customer.transactionCount} Transaktion{customer.transactionCount !== 1 ? 'en' : ''}
                      </p>
                    </div>
                  </div>
                  <p className="font-semibold text-gray-800">
                    {customer.totalAmount.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                  </p>
                </div>
              ))
            )}
          </div>
        </Card>
      </div>
    </div>
  );
};

