              </div>
            </div>
          </Card>

          {/* Ausbildungsfortschritt */}
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Ausbildungsfortschritt</h2>
            <div className="space-y-6">
              {customer.trainingProgress.map((section) => {
                let sectionBgClass = 'bg-gray-50 border-gray-200';
                let levelCircleBgClass = 'bg-gray-400';

                if (section.status === 'Aktuell') {
                  sectionBgClass = 'bg-pink-50 border-pink-200';
                } else if (section.status === 'Gesperrt') {
                  sectionBgClass = 'bg-green-50 border-green-200';
