            </div>
          </Card>

          {/* Konto-Übersicht (Summary Cards) */}
          <Card>
            <h2 className="text-xl font-semibold text-gray-900 mb-4">Konto-Übersicht</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
