    // Initialize all sections as collapsed by default
    const initialState: Record<number, boolean> = {};
    customers.find((c) => c.id === id)?.trainingProgress.forEach(section => {
      initialState[section.id] = false;
    });
    return initialState;
  });

  const customer = customers.find((c) => c.id === id); // Get customer from props

  if (!customer) {
    return (
      <div className="p-8 text-center text-red-600">
        Kunde mit ID "{id}" nicht gefunden.
        <Button variant="primary" onClick={() => navigate('/customers')} className="mt-4">
          Zurück zur Kundenliste
