const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>(INITIAL_MOCK_CUSTOMERS);
  const [transactions, setTransactions] = useState<Transaction[]>(INITIAL_MOCK_TRANSACTIONS);
  const [users, setUsers] = useState<User[]>(INITIAL_MOCK_USERS);
  const [isLoggedIn, setIsLoggedIn] = useState(false); // New state for login status
  const [loggedInUserEmail, setLoggedInUserEmail] = useState<string | null>(null); // Store logged in user's email
  const navigate = useNavigate();

  // Redirect to login page if not logged in
  useEffect(() => {
    if (!isLoggedIn && window.location.hash !== '#/login') {
      navigate('/login');
    } else if (isLoggedIn && window.location.hash === '#/login') {
      navigate('/');
    }
  }, [isLoggedIn, navigate]);

  // Find the current user based on loggedInUserEmail
  const currentUser = users.find(
    (user) => user.email === loggedInUserEmail
  ) || null;

  const handleLogin = (email: string, passwordInput: string): boolean => {
    const user = users.find(
      (u) => u.email === email && u.password === passwordInput
    );
    if (user) {
      setIsLoggedIn(true);
      setLoggedInUserEmail(user.email);
      navigate('/'); // Redirect to dashboard after successful login
      return true;
    }
    return false; // Login failed
  };

  const handleUpdateCustomer = (updatedCustomer: Customer) => {
    setCustomers(prevCustomers =>
      prevCustomers.map(c => (c.id === updatedCustomer.id ? updatedCustomer : c))
    );
  };

  const handleAddTransaction = (newTransaction: Transaction) => {
    setTransactions(prevTransactions => [...prevTransactions, newTransaction]);
  };

  // User management functions
  const handleAddUser = (newUser: User) => {
    setUsers(prevUsers => [...prevUsers, newUser]);
  };

  const handleUpdateUser = (updatedUser: User) => {
    setUsers(prevUsers =>
      prevUsers.map(u => (u.id === updatedUser.id ? updatedUser : u))
    );
  };

  const handleDeleteUser = (userId: string) => {
    setUsers(prevUsers => prevUsers.filter(u => u.id !== userId));
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setLoggedInUserEmail(null);
    alert('Sie wurden abgemeldet.');
    navigate('/login'); // Redirect to login page after logout
  };

  return (
    <div className="flex min-h-screen bg-gray-100">
      {isLoggedIn ? (
        <>
          <Sidebar appName="Mantrailing Card" currentUser={currentUser} onLogout={handleLogout} />
          <main className="flex-1 md:ml-64 p-0">
            <Routes>
              <Route path="/" element={<Dashboard customers={customers} transactions={transactions} />} />
              <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} />} />
              <Route
                path="/customers/:id"
                element={
                  <CustomerDetails
                    customers={customers}
                    transactions={transactions}
                    onUpdateCustomer={handleUpdateCustomer}
                    onAddTransaction={handleAddTransaction}
                  />
                }
              />
              <Route path="/reports" element={<Reports customers={customers} transactions={transactions} />} />
              <Route
                path="/users"
                element={
                  <UserManagement
                    users={users}
                    onAddUser={handleAddUser}
                    onUpdateUser={handleUpdateUser}
                    onDeleteUser={handleDeleteUser}
                  />
                }
              />
              {/* Fallback for any other path when logged in */}
              <Route path="*" element={<Dashboard customers={customers} transactions={transactions} />} />
            </Routes>
          </main>
        </>
      ) : (
        <Routes>
          <Route path="/login" element={<LoginPage onLogin={handleLogin} />} />
          {/* Redirect any other path to login if not logged in */}
          <Route path="*" element={<LoginPage onLogin={handleLogin} />} />
        </Routes>
      )}
    </div>
  );
};

export default App;

