  return (
    <Modal isOpen={isOpen} onClose={onClose} title={title} className="max-w-xl">
      <div className="p-0">
        <div className="max-h-[500px] overflow-y-auto custom-scrollbar p-6"> {/* Max height for scrollability */}
          {renderContent()}
