                const amountSign = isRecharge ? '+' : '-'; // Changed to dynamically show + or -

                return (
                  <div key={transaction.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div className="flex items-center">
                      <span className={`p-2 rounded-full bg-gray-200 mr-3 ${iconColor}`}>
                        <TransactionIcon className="h-5 w-5" />
                      </span>
                      <div>
                        <p className="font-medium text-gray-900">{customer?.firstName} {customer?.lastName}</p>
                        <p className="text-sm text-gray-500">{transaction.date} - {transaction.description}</p>
                      </div>
                    </div>
                    <p className={`font-semibold ${amountColor}`}>
                      {amountSign}{Math.abs(transaction.amount).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                    </p>
                  </div>
                );
              })
            )}
          </div>
        </Card>
      </div>

      <StatDetailModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={modalTitle}
        dataType={modalDataType}
        data={modalData}
      />
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import Card from '../components/Card';
import StatCard from '../components/StatCard';
import Table, { Column } from '../components/Table';
import Button from '../components/Button';
import Avatar from '../components/Avatar';
import { PlusIcon, ChevronRightIcon, UsersIcon, HeartIcon, ClipboardIcon, RepeatIcon, UserPlusIcon } from '../components/Icons';
import { ALPHABET, REFERENCE_DATE } from '../constants'; // Only ALPHABET and REFERENCE_DATE remain in constants
import { Customer, CustomerTableData, TrainingLevelEnum, Transaction, StatModalDataType, StatModalCustomerData, StatModalCustomerBalanceData, StatModalTransactionData } from '../types'; // Import types
import { useNavigate } from 'react-router-dom';
import { parseDateString, isSameMonth } from '../utils';
import StatDetailModal from '../components/StatDetailModal'; // Import StatDetailModal

interface CustomerManagementProps {
  customers: Customer[];
  transactions: Transaction[];
}

// Helper function to get color classes based on training level for the badge
const getLevelColorClass = (level: TrainingLevelEnum) => {
  switch (level) {
    case TrainingLevelEnum.EINSTEIGER:
      return 'bg-fuchsia-100 text-fuchsia-800'; // Orchid
    case TrainingLevelEnum.GRUNDLAGEN:
      return 'bg-lime-100 text-lime-800'; // Lime Green
    case TrainingLevelEnum.FORTGESCHRITTENE:
      return 'bg-sky-100 text-sky-800'; // Sky Blue
    case TrainingLevelEnum.MASTERCLASS:
      return 'bg-amber-100 text-amber-800'; // Peru
    case TrainingLevelEnum.EXPERT:
      return 'bg-indigo-100 text-indigo-800'; // Indigo
    default:
      return 'bg-gray-100 text-gray-800'; // Default
  }
};

// Helper function to get color classes based on training level for the avatar circle
const getAvatarColorForLevel = (level: TrainingLevelEnum) => {
  switch (level) {
    case TrainingLevelEnum.EINSTEIGER:
      return 'bg-fuchsia-500'; // Orchid (500-level for stronger color on avatar)
    case TrainingLevelEnum.GRUNDLAGEN:
      return 'bg-lime-500'; // Lime Green
    case TrainingLevelEnum.FORTGESCHRITTENE:
      return 'bg-sky-500'; // Sky Blue
    case TrainingLevelEnum.MASTERCLASS:
      return 'bg-amber-500'; // Peru
    case TrainingLevelEnum.EXPERT:
      return 'bg-indigo-500'; // Indigo
    default:
      return 'bg-gray-400'; // Default (a neutral grey)
  }
};


const CustomerManagement: React.FC<CustomerManagementProps> = ({ customers, transactions }) => {
  const navigate = useNavigate();
  const [activeFilter, setActiveFilter] = useState<string>('Alle');

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalTitle, setModalTitle] = useState('');
  const [modalDataType, setModalDataType] = useState<'customers' | 'transactions' | 'customerBalances' | 'activeCustomers'>('customers');
  const [modalData, setModalData] = useState<StatModalDataType>([]);

  // Dynamic calculations for Customer Management Stats
  const totalCustomers = customers.length;
  const totalBalance = customers.reduce((sum, c) => sum + c.balance, 0);

  const today = REFERENCE_DATE;
  const currentMonthTransactions = transactions.filter(t => {
    const transactionDate = parseDateString(t.date);
    return transactionDate && isSameMonth(transactionDate, today);
  });
  const monthlyTransactionsCount = currentMonthTransactions.length;

  // Determine active customers (those with transactions in the current month)
  const activeCustomerIds = new Set(
    currentMonthTransactions.map(t => t.customerId)
  );
  const activeCustomersCount = customers.filter(c => activeCustomerIds.has(c.id)).length;

  const handleStatCardClick = (title: string, type: 'customers' | 'transactions' | 'customerBalances' | 'activeCustomers', data: StatModalDataType) => {
    setModalTitle(title);
    setModalDataType(type);
    setModalData(data);
    setIsModalOpen(true);
  };

  // Prepare data for modals
  const allCustomersData: StatModalCustomerData[] = customers.map(c => ({
    id: c.id,
    avatarInitials: c.avatarInitials,
    avatarColor: c.avatarColor,
    name: `${c.firstName} ${c.lastName}`,
    dogName: c.dogName,
    balance: c.balance,
  }));

  const activeCustomersData: StatModalCustomerData[] = customers
    .filter(c => activeCustomerIds.has(c.id))
    .map(c => ({
      id: c.id,
      avatarInitials: c.avatarInitials,
      avatarColor: c.avatarColor,
      name: `${c.firstName} ${c.lastName}`,
      dogName: c.dogName,
      balance: c.balance,
    }));

  const customerBalancesData: StatModalCustomerBalanceData[] = [...customers]
    .sort((a, b) => b.balance - a.balance)
    .map(c => ({
      id: c.id,
      avatarInitials: c.avatarInitials,
      avatarColor: c.avatarColor,
      name: `${c.firstName} ${c.lastName}`,
      balance: c.balance,
    }));

  const currentMonthTransactionsData: StatModalTransactionData[] = currentMonthTransactions.map(t => {
    const customer = customers.find(c => c.id === t.customerId);
    return {
      id: t.id,
      customerId: t.customerId,
      customerName: customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt',
      date: t.date,
      description: t.description,
      amount: t.amount,
      type: t.type,
    };
  });


  const filteredCustomers = customers.filter((customer) => {
    if (activeFilter === 'Alle') {
      return true;
    }
    return customer.lastName.startsWith(activeFilter);
  });

  const customerTableData: CustomerTableData[] = filteredCustomers.map((customer) => ({
    id: customer.id,
    avatarInitials: customer.avatarInitials,
    avatarColor: customer.avatarColor, // This will be dynamically overridden in render
    name: `${customer.firstName} ${customer.lastName}\n${customer.id}`,
    dog: customer.dogName,
    balance: customer.balance,
    level: customer.level,
    createdAt: customer.createdAt,
  }));

  const columns: Column<CustomerTableData>[] = [
    {
      key: 'name',
      header: 'Kunde',
      render: (item: CustomerTableData) => (
        <div className="flex items-center">
          <Avatar
            initials={item.avatarInitials}
            color={getAvatarColorForLevel(item.level)} // Use level-specific color for avatar
            size="md"
            className="mr-3"
          />
          <div>
            <p className="font-medium text-gray-900">{item.name.split('\n')[0]}</p>
            <p className="text-sm text-gray-500">{item.name.split('\n')[1]}</p>
          </div>
        </div>
      ),
    },
    { key: 'dog', header: 'Hund' },
    {
      key: 'balance',
      header: 'Guthaben',
      render: (item: CustomerTableData) => item.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' }),
    },
    {
      key: 'level',
      header: 'Level',
      render: (item: CustomerTableData) => (
        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${getLevelColorClass(item.level)}`}>
          {item.level}
        </span>
      ),
    },
    { key: 'createdAt', header: 'Erstellt' },
    {
      key: 'id',
      header: '',
      render: (item: CustomerTableData) => (
        <ChevronRightIcon className="h-5 w-5 text-gray-400" />
      ),
      className: 'text-right',
    },
  ];

  const handleRowClick = (customerData: CustomerTableData) => {
    navigate(`/customers/${customerData.id}`);
  };

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <div className="flex justify-between items-center mb-2">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Kundenverwaltung</h1>
          <p className="text-gray-600">Verwalten Sie alle Ihre Kunden an einem Ort</p>
        </div>
        <Button variant="success" icon={UserPlusIcon}>
          Neuer Kunde
        </Button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 my-8">
        <StatCard
          title="Kunden Gesamt"
          value={totalCustomers}
          icon={UsersIcon}
          color="bg-green-100 text-green-700"
          onClick={() => handleStatCardClick('Alle Kunden', 'customers', allCustomersData)}
          isClickable={true}
        />
        <StatCard
          title="Aktiv"
          value={activeCustomersCount} // Dynamically calculated
          icon={HeartIcon}
          color="bg-orange-100 text-orange-700"
          onClick={() => handleStatCardClick('Aktive Kunden (dieser Monat)', 'activeCustomers', activeCustomersData)}
          isClickable={true}
        />
        <StatCard
          title="Guthaben"
          value={totalBalance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })} // Dynamically calculated
          icon={ClipboardIcon}
          color="bg-blue-100 text-blue-700"
          onClick={() => handleStatCardClick('Guthaben aller Kunden', 'customerBalances', customerBalancesData)}
          isClickable={true}
        />
        <StatCard
          title="Transaktionen Monat"
          value={monthlyTransactionsCount} // Dynamically calculated
          icon={RepeatIcon}
          color="bg-purple-100 text-purple-700"
          onClick={() => handleStatCardClick('Transaktionen dieses Monats', 'transactions', currentMonthTransactionsData)}
          isClickable={true}
        />
      </div>

      {/* Alphabet Filter */}
      <Card className="mb-6 px-4 py-2">
        <div className="flex flex-wrap justify-between gap-2">
          <button
            onClick={() => setActiveFilter('Alle')}
            className={`px-3 py-1.5 rounded-md text-sm font-medium transition-colors
              ${activeFilter === 'Alle' ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
          >
            Alle
          </button>
          {ALPHABET.map((letter) => (
            <button
              key={letter}
              onClick={() => setActiveFilter(letter)}
              className={`px-3 py-1.5 rounded-md text-sm font-medium transition-colors
                ${activeFilter === letter ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-700 hover:bg-gray-200'}`}
            >
              {letter}
            </button>
          ))}
        </div>
      </Card>

      {/* Customer List Table */}
      <Card>
        <h2 className="text-xl font-semibold text-gray-900 mb-4">Kundenliste ({filteredCustomers.length})</h2>
        <Table data={customerTableData} columns={columns} onRowClick={handleRowClick} />
      </Card>

      <StatDetailModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        title={modalTitle}
        dataType={modalDataType}
        data={modalData}
      />
    </div>
  );
};

export default CustomerManagement;

import React, { useState } from 'react';
import Card from '../components/Card';
import StatCard from '../components/StatCard';
import Button from '../components/Button';
import Select from '../components/Select';
import Avatar from '../components/Avatar';
import { MOCK_REPORT_TYPES, MOCK_REPORT_PERIODS, MOCK_REPORT_EMPLOYEES, REFERENCE_DATE } from '../constants'; // MOCK_TRANSACTIONS and MOCK_CUSTOMERS removed
import { ArrowUpCircleIcon, ArrowDownCircleIcon, DollarSignIcon, ClipboardIcon, UsersIcon } from '../components/Icons';
import { parseDateString, isSameMonth } from '../utils';
import { Customer, Transaction, StatModalDataType, StatModalTransactionData, StatModalCustomerData } from '../types'; // Import types
import StatDetailModal from '../components/StatDetailModal'; // Import StatDetailModal

interface ReportsProps {
  customers: Customer[];
  transactions: Transaction[];
}

const Reports: React.FC<ReportsProps> = ({ customers, transactions }) => {
  const [reportType, setReportType] = useState('Monatlich');
  // Initialize timePeriod to match the month of REFERENCE_DATE for consistency
  const defaultPeriodMonth = REFERENCE_DATE.toLocaleString('de-DE', { month: 'long' });
  const defaultPeriodYear = REFERENCE_DATE.getFullYear();
  const defaultTimePeriod = `${defaultPeriodMonth.charAt(0).toUpperCase() + defaultPeriodMonth.slice(1)} ${defaultPeriodYear}`;

  const [timePeriod, setTimePeriod] = useState(defaultTimePeriod);
  const [employee, setEmployee] = useState('Alle Mitarbeiter');

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalTitle, setModalTitle] = useState('');
  const [modalDataType, setModalDataType] = useState<'customers' | 'transactions' | 'customerBalances' | 'activeCustomers'>('customers');
  const [modalData, setModalData] = useState<StatModalDataType>([]);

  // Helper for parsing current filter period
  const getFilterPeriodDate = () => {
    if (timePeriod === 'Gesamt') return null;
    // Assuming timePeriod is in "Month YYYY" format for detailed filtering
    // For consistency with mock data, let's treat "Dezember 2025" as the REFERENCE_DATE's month
    const [monthName, year] = timePeriod.split(' ');
    // Simple mapping for German months to numbers (0-indexed)
    const monthMap: { [key: string]: number } = {
      'Januar': 0, 'Februar': 1, 'März': 2, 'April': 3, 'Mai': 4, 'Juni': 5,
      'Juli': 6, 'August': 7, 'September': 8, 'Oktober': 9, 'November': 10, 'Dezember': 11
    };
    const monthIndex = monthMap[monthName];
    if (monthIndex !== undefined && year) {
      return new Date(parseInt(year, 10), monthIndex, 1);
    }
    return null;
  };

  const selectedFilterPeriod = getFilterPeriodDate();

  // Filter transactions based on selected criteria
  const filteredTransactions = transactions.filter(t => { // Use transactions prop
    const transactionDate = parseDateString(t.date);
    if (!transactionDate) return false;

    // Filter by period
    let matchesPeriod = true;
    if (timePeriod === 'Gesamt') {
      matchesPeriod = true;
    } else if (selectedFilterPeriod) {
      matchesPeriod = isSameMonth(transactionDate, selectedFilterPeriod);
    }

    // Filter by employee
    const matchesEmployee = employee === 'Alle Mitarbeiter' || t.employee === employee;

    return matchesPeriod && matchesEmployee;
  });

  // Dynamic calculations for Report Stats
  const monthlyRecharges = filteredTransactions
    .filter(t => t.type === 'recharge')
    .reduce((sum, t) => sum + Math.abs(t.amount), 0);

  const monthlyDebits = filteredTransactions
    .filter(t => t.type === 'debit')
    .reduce((sum, t) => sum + Math.abs(t.amount), 0);

  const totalMonthlyTransactions = filteredTransactions.length;

  const activeCustomerIdsInPeriod = new Set(
    filteredTransactions.map(t => t.customerId)
  );
  const activeCustomersInPeriodCount = customers.filter(c => activeCustomerIdsInPeriod.has(c.id)).length; // Use customers prop


  const getTopCustomers = () => {
    const customerTransactions: { [key: string]: { count: number; totalAmount: number } } = {};
    filteredTransactions.forEach(t => {
      if (!customerTransactions[t.customerId]) {
        customerTransactions[t.customerId] = { count: 0, totalAmount: 0 };
      }
      customerTransactions[t.customerId].count++;
      customerTransactions[t.customerId].totalAmount += Math.abs(t.amount); // Consider total value
    });

    return Object.entries(customerTransactions)
      .sort(([, a], [, b]) => b.totalAmount - a.totalAmount) // Sort by total amount spent
      .slice(0, 3) // Get top 3
      .map(([customerId, data]) => {
        const customer = customers.find(c => c.id === customerId); // Use customers prop
        return {
          customerName: customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt',
          dogName: customer?.dogName || '',
          transactionCount: data.count,
          totalAmount: data.totalAmount,
          avatarInitials: customer?.avatarInitials || '?',
          avatarColor: customer?.avatarColor || 'bg-gray-400',
          id: customerId,
        };
      });
  };

  const topCustomers = getTopCustomers();

  const handleStatCardClick = (title: string, type: 'customers' | 'transactions' | 'customerBalances' | 'activeCustomers', data: StatModalDataType) => {
    setModalTitle(title);
    setModalDataType(type);
    setModalData(data);
    setIsModalOpen(true);
  };

  // Prepare data for modals based on filtered transactions/customers
  const allRechargesData: StatModalTransactionData[] = filteredTransactions
    .filter(t => t.type === 'recharge')
    .map(t => {
      const customer = customers.find(c => c.id === t.customerId);
      return {
        id: t.id,
        customerId: t.customerId,
        customerName: customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt',
        date: t.date,
        description: t.description,
        amount: t.amount,
        type: t.type,
      };
    });

  const allDebitsData: StatModalTransactionData[] = filteredTransactions
    .filter(t => t.type === 'debit')
    .map(t => {
      const customer = customers.find(c => c.id === t.customerId);
      return {
        id: t.id,
        customerId: t.customerId,
        customerName: customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt',
        date: t.date,
        description: t.description,
        amount: t.amount,
        type: t.type,
      };
    });

  const allFilteredTransactionsData: StatModalTransactionData[] = filteredTransactions.map(t => {
    const customer = customers.find(c => c.id === t.customerId);
    return {
      id: t.id,
      customerId: t.customerId,
      customerName: customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt',
      date: t.date,
      description: t.description,
      amount: t.amount,
      type: t.type,
    };
  });

  const activeCustomersReportData: StatModalCustomerData[] = customers
    .filter(c => activeCustomerIdsInPeriod.has(c.id))
    .map(c => ({
      id: c.id,
      avatarInitials: c.avatarInitials,
      avatarColor: c.avatarColor,
      name: `${c.firstName} ${c.lastName}`,
      dogName: c.dogName,
      balance: c.balance,
    }));


  return (
    <div className="p-6 md:p-8 lg:p-10">
      <h1 className="text-3xl font-bold text-gray-900 mb-2">Berichte & Statistiken</h1>
      <p className="text-gray-600 mb-8">Analysieren und exportieren Sie Ihre Geschäftsdaten</p>

      {/* Filters and Export Buttons */}
      <Card className="mb-8">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 items-end">
          <Select
            id="reportType"
            label="Berichtstyp"
            options={MOCK_REPORT_TYPES.map(type => ({ value: type, label: type }))}
            value={reportType}
            onChange={(e) => setReportType(e.target.value)}
          />
          <Select
            id="timePeriod"
            label="Zeitraum"
            options={MOCK_REPORT_PERIODS.map(period => ({ value: period, label: period }))}
            value={timePeriod}
            onChange={(e) => setTimePeriod(e.target.value)}
          />
          <Select
            id="employee"
            label="Mitarbeiter"
            options={MOCK_REPORT_EMPLOYEES.map(emp => ({ value: emp, label: emp }))}
            value={employee}
            onChange={(e) => setEmployee(e.target.value)}
          />
          <Button variant="outline" className="w-full lg:w-auto">
            Als CSV exportieren
          </Button>
          <Button variant="success" className="w-full lg:w-auto">
            Als PDF exportieren
          </Button>
        </div>
      </Card>

      {/* Stats Cards for Reports */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <StatCard
          title="Gesamtaufladungen (Monat)"
          value={monthlyRecharges.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
          icon={UsersIcon}
          color="bg-green-100 text-green-700"
          onClick={() => handleStatCardClick('Gesamtaufladungen im Zeitraum', 'transactions', allRechargesData)}
          isClickable={true}
        />
        <StatCard
          title="Abbuchungen (Monat)"
          value={monthlyDebits.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
          icon={DollarSignIcon}
          color="bg-orange-100 text-orange-700"
          onClick={() => handleStatCardClick('Abbuchungen im Zeitraum', 'transactions', allDebitsData)}
          isClickable={true}
        />
        <StatCard
          title="Transaktionen"
          value={totalMonthlyTransactions}
          icon={ClipboardIcon}
          color="bg-blue-100 text-blue-700"
          onClick={() => handleStatCardClick('Alle Transaktionen im Zeitraum', 'transactions', allFilteredTransactionsData)}
          isClickable={true}
        />
        <StatCard
          title="Aktive Kunden"
          value={activeCustomersInPeriodCount}
          icon={UsersIcon}
          color="bg-purple-100 text-purple-700"
          onClick={() => handleStatCardClick('Aktive Kunden im Zeitraum', 'activeCustomers', activeCustomersReportData)}
          isClickable={true}
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Transaktionen im Zeitraum */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Transaktionen im Zeitraum ({filteredTransactions.length})</h2>
          <div className="space-y-4 max-h-96 overflow-y-auto custom-scrollbar"> {/* Added max-h and overflow for scroll */}
            {filteredTransactions.length === 0 ? (
              <p className="text-gray-500">Keine Transaktionen für den ausgewählten Zeitraum und Mitarbeiter gefunden.</p>
            ) : (
              filteredTransactions.map((transaction) => {
                const customer = customers.find(c => c.id === transaction.customerId); // Use customers prop
                const isRecharge = transaction.type === 'recharge';
                const TransactionIcon = isRecharge ? ArrowUpCircleIcon : ArrowDownCircleIcon;
                const iconColor = isRecharge ? 'text-green-500' : 'text-red-500';
                const amountColor = isRecharge ? 'text-green-700' : 'text-red-700';
                const amountSign = isRecharge ? '+' : '-';

                return (
                  <div key={transaction.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <div className="flex items-center">
                      <span className={`p-2 rounded-full bg-gray-200 mr-3 ${iconColor}`}>
                        <TransactionIcon className="h-5 w-5" />
                      </span>
                      <div>
                        <p className="font-medium text-gray-900">{transaction.description}</p>
                        <p className="text-sm text-gray-500">
                          {transaction.date} von {transaction.employee}
                          {customer && ` für ${customer.firstName} ${customer.lastName}`}
                        </p>
                      </div>
                    </div>
                    <p className={`font-semibold ${amountColor}`}>
                      {amountSign}{Math.abs(transaction.amount).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                    </p>
                  </div>
                );
              })
            )}
          </div>
        </Card>

        {/* Top Kunden im Zeitraum */}
        <Card>
          <h2 className="text-xl font-semibold text-gray-900 mb-4">Top Kunden im Zeitraum</h2>
          <div className="space-y-4 max-h-96 overflow-y-auto custom-scrollbar"> {/* Added max-h and overflow for scroll */}
            {topCustomers.length === 0 ? (
              <p className="text-gray-500">Keine Top-Kunden für den ausgewählten Zeitraum und Mitarbeiter gefunden.</p>
            ) : (
              topCustomers.map((customer, index) => (
                <div key={customer.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <div className="flex items-center">
                    <span className="text-lg font-bold text-gray-700 mr-3">{index + 1}.</span>
                    <Avatar initials={customer.avatarInitials} color={customer.avatarColor} size="md" className="mr-3" />
                    <div>
                      <p className="font-medium text-gray-900">{customer.customerName}</p>
                      <p className="text-sm text-gray-500">
