              <div key={item.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                <div className="flex items-center">
                  <Avatar initials={item.avatarInitials} color={item.avatarColor} size="sm" className="mr-3" />
                  <p className="font-medium text-gray-900">{item.name}</p>
                </div>
                <p className="font-semibold text-gray-800">{item.balance.toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}</p>
              </div>
            ))}
          </div>
        );
      case 'transactions':
        const transactionData = data as StatModalTransactionData[];
        return (
          <div className="space-y-3">
            {transactionData.map((item) => {
              const isRecharge = item.type === 'recharge';
              const TransactionIcon = isRecharge ? ArrowUpCircleIcon : ArrowDownCircleIcon;
              const iconColor = isRecharge ? 'text-green-500' : 'text-red-500';
              const amountColor = isRecharge ? 'text-green-700' : 'text-red-700';
              const amountSign = isRecharge ? '+' : '-';

              return (
                <div key={item.id} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                  <div className="flex items-center">
                    <span className={`p-2 rounded-full bg-gray-200 mr-3 ${iconColor}`}>
                      <TransactionIcon className="h-5 w-5" />
                    </span>
                    <div>
                      <p className="font-medium text-gray-900">{item.customerName}</p>
                      <p className="text-xs text-gray-500">{item.date} - {item.description}</p>
                    </div>
                  </div>
                  <p className={`font-semibold ${amountColor}`}>
                    {amountSign}{Math.abs(item.amount).toLocaleString('de-DE', { style: 'currency', currency: 'EUR' })}
                  </p>
                </div>
              );
            })}
          </div>
        );
      default:
        return <p className="text-gray-500">Unbekannter Datentyp.</p>;
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={title} className="max-w-xl"> {/* Title prop passed to Modal */}
      {/* Content area, wrapped in p-0 to override Modal's default padding */}
      <div className="p-0">
        <div className="max-h-[500px] overflow-y-auto custom-scrollbar p-6 bg-gray-50 min-h-[150px]">
          {renderContent()}
        </div>
      </div>
    </Modal>
  );
};

