    name: `${c.firstName} ${c.lastName}`,
    dogName: c.dogName,
    balance: c.balance,
  }));

  const activeCustomersData: StatModalCustomerData[] = customers
    .filter(c => activeCustomerIds.has(c.id))
    .map(c => ({
      id: c.id,
      avatarInitials: c.avatarInitials,
      avatarColor: c.avatarColor,
      name: `${c.firstName} ${c.lastName}`,
      dogName: c.dogName,
      balance: c.balance,
    }));

  const customerBalancesData: StatModalCustomerBalanceData[] = [...customers]
    .sort((a, b) => b.balance - a.balance)
    .map(c => ({
      id: c.id,
      avatarInitials: c.avatarInitials,
      avatarColor: c.avatarColor,
      name: `${c.firstName} ${c.lastName}`,
      balance: c.balance,
    }));

  const currentMonthTransactionsData: StatModalTransactionData[] = currentMonthTransactions.map(t => {
    const customer = customers.find(c => c.id === t.customerId);
    return {
      id: t.id,
      customerId: t.customerId,
      customerName: customer ? `${customer.firstName} ${customer.lastName}` : 'Unbekannt',
      date: t.date,
      description: t.description,
      amount: t.amount,
      type: t.type,
