          <p className="text-sm text-gray-700">Zeitraum: <span className="font-medium">{timePeriod}</span></p>
          <p className="text-sm text-gray-700">Mitarbeiter: <span className="font-medium">{employee}</span></p>
        </div>

        {/* Stats Cards for Reports */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
          <StatCard
            title="Gesamtaufladungen (Monat)"
