      alert('PDF-Exportdienst nicht verfügbar. Bitte überprüfen Sie die Browser-Konsole für Details.');
      setIsPdfExporting(false);
      return;
    }

    if (element) {
      const filename = `Bericht-${timePeriod.replace(/ /g, '-')}-${reportType.replace(/ /g, '-')}.pdf`;
      try {
        await html2pdf().from(element).set({
          margin: [10, 10, 10, 10], // Top, Left, Bottom, Right
          filename: filename,
          html2canvas: { scale: 2, logging: true, dpi: 192, letterRendering: true },
          jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
          worker: { auto: false } // Disable Web Workers to prevent postMessage serialization errors
        }).save();
        setIsPdfExporting(false);
      } catch (error) {
        console.error('PDF Exportfehler in Komponente abgefangen:', error);
        alert('Fehler beim Exportieren des PDF-Berichts. Details in der Konsole.');
        setIsPdfExporting(false);
