      {/* Filters and Export Buttons */}
      <Card className="mb-8">
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 items-end">
          <Select
            id="reportType"
            label="Berichtstyp"
            options={MOCK_REPORT_TYPES.map(type => ({ value: type, label: type }))}
            value={reportType}
            onChange={(e) => setReportType(e.target.value)}
          />
          <Select
            id="timePeriod"
            label="Zeitraum"
            options={MOCK_REPORT_PERIODS.map(period => ({ value: period, label: period }))}
            value={timePeriod}
            onChange={(e) => setTimePeriod(e.target.value)}
          />
          <Select
            id="employee"
            label="Mitarbeiter"
            options={MOCK_REPORT_EMPLOYEES.map(emp => ({ value: emp, label: emp }))}
            value={employee}
            onChange={(e) => setEmployee(e.target.value)}
          />
          {/* Removed "Als CSV exportieren" button */}
          <Button
            variant="success"
            className="w-full lg:w-auto"
            onClick={handleExportPdf}
            disabled={isPdfExporting}
          >
            {isPdfExporting ? 'PDF wird generiert...' : 'Als PDF exportieren'}
