const App: React.FC = () => {
  const [customers, setCustomers] = useState<Customer[]>(INITIAL_MOCK_CUSTOMERS);
  const [transactions, setTransactions] = useState<Transaction[]>(INITIAL_MOCK_TRANSACTIONS);
  // User management state for `UserManagement` page - separate from Supabase auth users for now
  const [managedUsers, setManagedUsers] = useState<UserTableData[]>(INITIAL_MOCK_USERS); 

  const [session, setSession] = useState<Session | null>(null);
  const [profile, setProfile] = useState<Profile | null>(null); // Our custom profile with role
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      setLoading(false);
    });

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      setLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    const fetchProfile = async (userId: string) => {
      setLoading(true);
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      if (error) {
        console.error('Error fetching profile:', error);
        setProfile(null);
      } else if (data) {
        setProfile(data as Profile); // Cast to our Profile interface
      }
      setLoading(false);
    };

    if (session?.user) {
      fetchProfile(session.user.id);
    } else {
      setProfile(null);
      setLoading(false);
    }
  }, [session]);

  // Handle redirects based on auth status and user role
  useEffect(() => {
    if (loading) return;

    // If not logged in, redirect to login page
    if (!session) {
      if (location.pathname !== '/login') {
        navigate('/login');
      }
      return;
    }

    // If logged in but no profile yet (should not happen often if RLS is set for reading profiles)
    if (session && !profile && !loading) {
      // You might want to show a loading spinner or an error if profile can't be fetched
      console.warn('User is logged in but profile could not be fetched.');
      // Optionally navigate to a page indicating a profile error or logout
      return;
    }

    // If logged in and profile is available
    if (session && profile) {
      // Redirect from login page if already logged in
      if (location.pathname === '/login') {
        navigate('/');
        return;
      }

      // Role-based routing
      const userRole = profile.role;
      const customerId = profile.customer_id;

      switch (userRole) {
        case UserRoleEnum.ADMIN:
          // Admin has full access, no specific redirects unless on login page
          break;
        case UserRoleEnum.MITARBEITER:
          // Employee can access Dashboard and CustomerManagement
          if (!['/', '/customers', '/customers/:id'].some(path => location.pathname.startsWith(path.replace(':id', '')))) {
            alert('Sie haben keine Berechtigung für diese Seite.');
            navigate('/'); // Redirect to Dashboard
          }
          break;
        case UserRoleEnum.KUNDE:
          // Customer can ONLY access their own customer card
          if (!customerId) {
            alert('Ihr Kundenprofil ist nicht mit einer Kundenkarte verknüpft.');
            supabase.auth.signOut(); // Log out if no customerId
            navigate('/login');
            return;
          }
          const expectedCustomerPath = `/customers/${customerId}`;
          if (location.pathname !== expectedCustomerPath) {
            alert('Sie haben nur Zugriff auf Ihre eigene Kundenkarte.');
            navigate(expectedCustomerPath);
          }
          break;
        default:
          alert('Ihre Rolle ist nicht definiert. Bitte kontaktieren Sie den Administrator.');
          supabase.auth.signOut();
          navigate('/login');
          break;
      }
    }
  }, [session, profile, loading, navigate, location.pathname]);


  const handleUpdateCustomer = (updatedCustomer: Customer) => {
    setCustomers(prevCustomers =>
      prevCustomers.map(c => (c.id === updatedCustomer.id ? updatedCustomer : c))
    );
  };

  const handleAddTransaction = (newTransaction: Transaction) => {
    setTransactions(prevTransactions => [...prevTransactions, newTransaction]);
  };

  // User management functions (for UserManagement page, still mock-based)
  const handleAddUser = (userData: { firstName: string; lastName: string; email: string; role: UserRoleEnum }) => {
    const newUserId = `user-${managedUsers.length + 1}-${Date.now()}`;
    const initials = `${userData.firstName.charAt(0)}${userData.lastName.charAt(0)}`.toUpperCase().slice(0, 2);
    const avatarColors = ['bg-red-500', 'bg-orange-500', 'bg-purple-500', 'bg-indigo-500', 'bg-blue-500', 'bg-green-500'];
    const randomColor = avatarColors[Math.floor(Math.random() * avatarColors.length)];

    const newUser: UserTableData = {
      id: newUserId,
      avatarInitials: initials,
      avatarColor: randomColor,
      firstName: userData.firstName,
      lastName: userData.lastName,
      email: userData.email,
      role: userData.role,
      createdAt: REFERENCE_DATE.toLocaleDateString('de-DE'),
      name: `${userData.firstName} ${userData.lastName}`.trim(),
    };
    setManagedUsers(prevUsers => [...prevUsers, newUser]);
  };

  const handleUpdateUser = (updatedUser: UserTableData) => {
    setManagedUsers(prevUsers =>
      prevUsers.map(u => (u.id === updatedUser.id ? updatedUser : u))
    );
  };

  const handleDeleteUser = (userId: string) => {
    setManagedUsers(prevUsers => prevUsers.filter(u => u.id !== userId));
  };

  const handleLogout = async () => {
    setLoading(true);
    const { error } = await supabase.auth.signOut();
    if (error) {
      console.error('Error logging out:', error.message);
      alert('Fehler beim Abmelden.');
    } else {
      console.log('Successfully logged out.');
      setSession(null);
      setProfile(null);
      navigate('/login');
    }
    setLoading(false);
  };

  // Filtered navigation items based on user role
  const getFilteredNavigationItems = () => {
    if (!profile) return [];
    switch (profile.role) {
      case UserRoleEnum.ADMIN:
        return NAVIGATION_ITEMS;
      case UserRoleEnum.MITARBEITER:
        return NAVIGATION_ITEMS.filter(item =>
          item.path === '/' || item.path === '/customers'
        );
      case UserRoleEnum.KUNDE:
        return []; // Customers don't see the sidebar
      default:
        return [];
    }
  };

  const filteredNavigationItems = getFilteredNavigationItems();
  const showSidebar = profile?.role !== UserRoleEnum.KUNDE && session; // Don't show sidebar for customers

  if (loading) {
    // Basic loading spinner or splash screen
    return (
      <div className="flex items-center justify-center min-h-screen w-full bg-gray-100">
        <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-blue-500 border-solid"></div>
        <p className="ml-4 text-lg text-gray-700">Lade...</p>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-gray-100">
      {session && profile ? (
        <>
          {showSidebar && (
            <Sidebar
              appName="Mantrailing Card"
              currentUser={{
                id: profile.id,
                email: profile.email,
                profile: profile, // Pass the whole profile object
              }}
              onLogout={handleLogout}
              navigationItems={filteredNavigationItems} // Pass filtered items to Sidebar
            />
          )}
          <main className={`flex-1 p-0 ${showSidebar ? 'md:ml-64' : ''}`}>
            <Routes>
              {/* Admin Routes */}
              {profile.role === UserRoleEnum.ADMIN && (
                <>
                  <Route path="/" element={<Dashboard customers={customers} transactions={transactions} />} />
                  <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUserRole={profile.role} />} />
                  <Route
                    path="/customers/:id"
                    element={
                      <CustomerDetails
                        customers={customers}
                        transactions={transactions}
                        onUpdateCustomer={handleUpdateCustomer}
                        onAddTransaction={handleAddTransaction}
                        currentUserRole={profile.role}
                        currentUserId={profile.id}
                        currentUserCustomerId={profile.customer_id}
                      />
                    }
                  />
                  <Route path="/reports" element={<Reports customers={customers} transactions={transactions} />} />
                  <Route
                    path="/users"
                    element={
                      <UserManagement
                        users={managedUsers} // Use managedUsers for the UserManagement page
                        onAddUser={handleAddUser}
                        onUpdateUser={handleUpdateUser}
                        onDeleteUser={handleDeleteUser}
                        currentUserRole={profile.role}
                      />
                    }
                  />
                  {/* Admin Fallback */}
                  <Route path="*" element={<Dashboard customers={customers} transactions={transactions} />} />
                </>
              )}

              {/* Employee Routes */}
              {profile.role === UserRoleEnum.MITARBEITER && (
                <>
                  <Route path="/" element={<Dashboard customers={customers} transactions={transactions} />} />
                  <Route path="/customers" element={<CustomerManagement customers={customers} transactions={transactions} currentUserRole={profile.role} />} />
                  <Route
                    path="/customers/:id"
                    element={
                      <CustomerDetails
                        customers={customers}
                        transactions={transactions}
                        onUpdateCustomer={handleUpdateCustomer}
                        onAddTransaction={handleAddTransaction}
                        currentUserRole={profile.role}
                        currentUserId={profile.id}
                        currentUserCustomerId={profile.customer_id}
                      />
                    }
                  />
                  {/* Employee attempts to access unauthorized routes -> handled by useEffect redirect */}
                  <Route path="*" element={<Dashboard customers={customers} transactions={transactions} />} />
                </>
              )}

              {/* Customer Routes */}
              {profile.role === UserRoleEnum.KUNDE && profile.customer_id && (
                <>
                  <Route
                    path={`/customers/${profile.customer_id}`}
                    element={
                      <CustomerDetails
                        customers={customers}
                        transactions={transactions}
                        onUpdateCustomer={handleUpdateCustomer}
                        onAddTransaction={handleAddTransaction}
                        currentUserRole={profile.role}
                        currentUserId={profile.id}
                        currentUserCustomerId={profile.customer_id}
                      />
                    }
                  />
                  {/* Customer Fallback - always redirect to their own card */}
                  <Route path="*" element={<CustomerDetails
                    customers={customers}
                    transactions={transactions}
                    onUpdateCustomer={handleUpdateCustomer}
                    onAddTransaction={handleAddTransaction}
                    currentUserRole={profile.role}
                    currentUserId={profile.id}
                    currentUserCustomerId={profile.customer_id}
                  />} />
                </>
              )}
            </Routes>
          </main>
        </>
      ) : (
        <Routes>
          <Route path="/login" element={<LoginPage onLogin={async (email, password) => {
            setLoading(true);
            const { error } = await supabase.auth.signInWithPassword({ email, password });
            setLoading(false);
            if (error) {
              console.error('Login error:', error.message);
              return false;
            }
            return true;
          }} />} />
          {/* Redirect any other path to login if not logged in */}
          <Route path="*" element={<LoginPage onLogin={async (email, password) => {
            setLoading(true);
            const { error } = await supabase.auth.signInWithPassword({ email, password });
            setLoading(false);
            if (error) {
              console.error('Login error:', error.message);
              return false;
            }
            return true;
          }} />} />
        </Routes>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import Card from '../components/Card';
import Table, { Column } from '../components/Table';
import Button from '../components/Button';
import Avatar from '../components/Avatar';
import UserFormModal from '../components/UserFormModal'; // New modal for add/edit user
import UserDeleteConfirmationModal from '../components/UserDeleteConfirmationModal'; // New modal for delete confirmation
import { PlusIcon, EditIcon, TrashIcon, UserPlusIcon } from '../components/Icons';
import { UserTableData, UserRoleEnum } from '../types';
import { REFERENCE_DATE } from '../constants';

interface UserManagementProps {
  users: UserTableData[];
  onAddUser: (newUser: UserTableData) => void;
  onUpdateUser: (updatedUser: UserTableData) => void;
  onDeleteUser: (userId: string) => void;
}

const UserManagement: React.FC<UserManagementProps> = ({ users, onAddUser, onUpdateUser, onDeleteUser }) => {
  const [showUserFormModal, setShowUserFormModal] = useState(false);
  const [userToEdit, setUserToEdit] = useState<UserTableData | null>(null); // State to hold user being edited
  const [showDeleteConfirmationModal, setShowDeleteConfirmationModal] = useState(false);
  const [userToDeleteId, setUserToDeleteId] = useState<string | null>(null);

  const handleOpenAddUserModal = () => {
    setUserToEdit(null); // Clear userToEdit for add mode
    setShowUserFormModal(true);
  };

  const handleOpenEditUserModal = (user: UserTableData) => {
    setUserToEdit(user);
    setShowUserFormModal(true);
  };

  const handleCloseUserFormModal = () => {
    setShowUserFormModal(false);
    setUserToEdit(null);
  };

  const handleSubmitUserForm = (userData: { firstName: string; lastName: string; email: string; role: UserRoleEnum }) => {
    // The `name` property is derived for `UserTableData` and not stored directly in `User`.
    if (userToEdit) {
      // Update existing user
      const updatedUser: UserTableData = {
        ...userToEdit,
        firstName: userData.firstName,
        lastName: userData.lastName,
        email: userData.email,
        role: userData.role,
        name: `${userData.firstName} ${userData.lastName}`.trim(), // Ensure `name` is updated
      };
      onUpdateUser(updatedUser);
    } else {
      // Add new user
      const newUserId = `user-${users.length + 1}-${Date.now()}`;
      // Generate initials from first and last name
      const initials = `${userData.firstName.charAt(0)}${userData.lastName.charAt(0)}`.toUpperCase().slice(0, 2);
      const avatarColors = ['bg-red-500', 'bg-orange-500', 'bg-purple-500', 'bg-indigo-500', 'bg-blue-500', 'bg-green-500'];
      const randomColor = avatarColors[Math.floor(Math.random() * avatarColors.length)];

      const newUser: UserTableData = {
        id: newUserId,
        avatarInitials: initials,
        avatarColor: randomColor,
        firstName: userData.firstName,
        lastName: userData.lastName,
        email: userData.email,
        role: userData.role,
        createdAt: REFERENCE_DATE.toLocaleDateString('de-DE'), // Use REFERENCE_DATE for consistency
        name: `${userData.firstName} ${userData.lastName}`.trim(), // Add derived `name`
      };
      onAddUser(newUser);
    }
    handleCloseUserFormModal();
  };

  const handleOpenDeleteConfirmation = (userId: string) => {
    setUserToDeleteId(userId);
    setShowDeleteConfirmationModal(true);
  };

  const handleConfirmDelete = () => {
    if (userToDeleteId) {
      onDeleteUser(userToDeleteId);
    }
    setShowDeleteConfirmationModal(false);
    setUserToDeleteId(null);
  };

  const handleCloseDeleteConfirmation = () => {
    setShowDeleteConfirmationModal(false);
    setUserToDeleteId(null);
  };

  const userTableData: UserTableData[] = users.map(user => ({
    id: user.id,
    avatarInitials: user.avatarInitials,
    avatarColor: user.avatarColor,
    name: `${user.firstName} ${user.lastName}`.trim(), // Combine first and last name for display
    firstName: user.firstName,
    lastName: user.lastName,
    email: user.email,
    role: user.role,
    createdAt: user.createdAt,
  }));

  const columns: Column<UserTableData>[] = [
    {
      key: 'name',
      header: 'BENUTZER',
      render: (item: UserTableData) => (
        <div className="flex items-center">
          <Avatar initials={item.avatarInitials} color={item.avatarColor} size="md" className="mr-3" />
          <p className="font-medium text-gray-900">{item.name}</p>
        </div>
      ),
    },
    { key: 'email', header: 'E-MAIL' },
    {
      key: 'role',
      header: 'ROLLE',
      render: (item: UserTableData) => (
        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium
          ${item.role === UserRoleEnum.ADMIN ? 'bg-red-100 text-red-800' : 'bg-blue-100 text-blue-800'}`}
        >
          {item.role}
        </span>
      ),
    },
    { key: 'createdAt', header: 'ERSTELLT' },
    {
      key: 'id',
      header: 'AKTIONEN',
      render: (item: UserTableData) => (
        <div className="flex items-center space-x-3">
          <button
            onClick={(e) => { e.stopPropagation(); handleOpenEditUserModal(users.find(u => u.id === item.id)!); }}
            className="text-gray-500 hover:text-blue-600"
            aria-label={`Benutzer ${item.name} bearbeiten`}
          >
            <EditIcon className="h-5 w-5" />
          </button>
          <button
            onClick={(e) => { e.stopPropagation(); handleOpenDeleteConfirmation(item.id); }}
            className="text-gray-500 hover:text-red-600"
            aria-label={`Benutzer ${item.name} löschen`}
          >
            <TrashIcon className="h-5 w-5" />
          </button>
        </div>
      ),
      className: 'text-right',
    },
  ];

  const userToDelete = users.find(u => u.id === userToDeleteId);

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <div className="flex justify-between items-center mb-2">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Benutzerverwaltung</h1>
          <p className="text-gray-600">Verwalten Sie alle Systembenutzer an einem Ort</p>
        </div>
        <Button variant="success" icon={UserPlusIcon} onClick={handleOpenAddUserModal}>
          Neuer Benutzer
        </Button>
      </div>

      <Card className="mt-8">
        <h2 className="text-xl font-semibold text-gray-900 mb-4">Systembenutzer ({users.length})</h2>
        <Table data={userTableData} columns={columns} />
      </Card>

      <UserFormModal
        isOpen={showUserFormModal}
        onClose={handleCloseUserFormModal}
        onSubmit={handleSubmitUserForm}
        userToEdit={userToEdit}
      />

      <UserDeleteConfirmationModal
        isOpen={showDeleteConfirmationModal}
        onClose={handleCloseDeleteConfirmation}
        onConfirm={handleConfirmDelete}
        userNameToDelete={userToDelete ? `${userToDelete.firstName} ${userToDelete.lastName}`.trim() : ''}
      />
    </div>
  );
};

export default UserManagement;

import React, { useState, useEffect } from 'react';
import Modal from './Modal';
import Button from './Button';
import Input from './Input';
import Select from './Select';
import { UserTableData, UserRoleEnum } from '../types';

interface UserFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (userData: { firstName: string; lastName: string; email: string; role: UserRoleEnum }) => void;
  userToEdit: UserTableData | null;
}

const UserFormModal: React.FC<UserFormModalProps> = ({ isOpen, onClose, onSubmit, userToEdit }) => {
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [email, setEmail] = useState('');
  const [role, setRole] = useState<UserRoleEnum>(UserRoleEnum.MITARBEITER);
  const [firstNameError, setFirstNameError] = useState('');
  const [lastNameError, setLastNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  useEffect(() => {
    if (userToEdit) {
      setFirstName(userToEdit.firstName);
      setLastName(userToEdit.lastName);
      setEmail(userToEdit.email);
      setRole(userToEdit.role);
    } else {
      // Reset form for new user
      setFirstName('');
      setLastName('');
      setEmail('');
      setRole(UserRoleEnum.MITARBEITER);
    }
    setFirstNameError('');
    setLastNameError('');
    setEmailError('');
  }, [userToEdit, isOpen]); // Reset when modal opens or userToEdit changes

  const validateForm = () => {
    let isValid = true;
    if (!firstName.trim()) {
      setFirstNameError('Vorname ist erforderlich.');
      isValid = false;
    } else {
      setFirstNameError('');
    }

    if (!lastName.trim()) {
      setLastNameError('Nachname ist erforderlich.');
      isValid = false;
    } else {
      setLastNameError('');
    }

    if (!email.trim()) {
      setEmailError('E-Mail ist erforderlich.');
      isValid = false;
    } else if (!/\S+@\S+\.\S+/.test(email)) { // Basic email format validation
      setEmailError('Ungültiges E-Mail-Format.');
      isValid = false;
    } else {
      setEmailError('');
    }
    return isValid;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validateForm()) {
      onSubmit({ firstName, lastName, email, role });
    }
  };

  const title = userToEdit ? 'Benutzer bearbeiten' : 'Neuen Benutzer erstellen';

  const roleOptions = [
    { value: UserRoleEnum.ADMIN, label: 'Admin' },
    { value: UserRoleEnum.MITARBEITER, label: 'Mitarbeiter' },
  ];

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={title} className="max-w-md">
      <form onSubmit={handleSubmit} className="p-0">
        <div className="space-y-4">
          <Input
            id="userFirstName"
            label="Vorname"
            type="text"
            value={firstName}
            onChange={(e) => setFirstName(e.target.value)}
            placeholder="Max"
            error={firstNameError}
          />
          <Input
            id="userLastName"
            label="Nachname"
            type="text"
            value={lastName}
            onChange={(e) => setLastName(e.target.value)}
            placeholder="Mustermann"
            error={lastNameError}
          />
          <Input
            id="userEmail"
            label="E-Mail"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="max.mustermann@example.com"
            error={emailError}
          />
          <Select
            id="userRole"
            label="Rolle"
            options={roleOptions}
            value={role}
            onChange={(e) => setRole(e.target.value as UserRoleEnum)}
          />
        </div>
        <div className="p-4 border-t border-gray-200 mt-6 flex justify-end space-x-3">
          <Button variant="outline" onClick={onClose} type="button">
            Abbrechen
          </Button>
          <Button variant="success" type="submit">
            Speichern
          </Button>
        </div>
      </form>
    </Modal>
  );
};

export default UserFormModal;

