import { Customer, Transaction, TrainingLevelEnum, AppUser, UserRoleEnum, Profile, UserTableData } from './types'; // Import types
import { REFERENCE_DATE, NAVIGATION_ITEMS } from './constants'; // Import constants needed for initial state
import { createClient, Session, User } from '@supabase/supabase-js'; // Import Supabase types

// Supabase Client Initialization
// IMPORTANT: For this specific online development environment where .env files cannot be managed,
// the Supabase URL and Anon Key are hardcoded directly into the application.
// In a production environment or when developing locally, these values MUST be loaded
