import React, { useState, useEffect } from 'react';
import Modal from './Modal';
import Button from './Button';
import Input from './Input';
import Select from './Select';
import { UserTableData, UserRoleEnum } from '../types';

interface UserFormModalProps {
  isOpen: boolean;
  onClose: () => void;
  // Updated onSubmit to also accept a password for new user creation
  onSubmit: (userData: { first_name: string; last_name: string; email: string; role: UserRoleEnum; password?: string }) => void;
  userToEdit: UserTableData | null;
}

const UserFormModal: React.FC<UserFormModalProps> = ({ isOpen, onClose, onSubmit, userToEdit }) => {
  const [first_name, setFirstName] = useState(''); // Changed to first_name
  const [last_name, setLastName] = useState('');   // Changed to last_name
  const [email, setEmail] = useState('');
  const [role, setRole] = useState<UserRoleEnum>(UserRoleEnum.MITARBEITER);
  const [password, setPassword] = useState(''); // New state for password
  const [firstNameError, setFirstNameError] = useState('');
  const [lastNameError, setLastNameError] = useState('');
  const [emailError, setEmailError] = useState('');
  const [passwordError, setPasswordError] = useState(''); // New state for password error

  useEffect(() => {
    if (userToEdit) {
      setFirstName(userToEdit.first_name); // Use userToEdit.first_name
      setLastName(userToEdit.last_name);   // Use userToEdit.last_name
      setEmail(userToEdit.email);
      setRole(userToEdit.role);
      setPassword(''); // Password is not editable
    } else {
      // Reset form for new user
      setFirstName('');
      setLastName('');
      setEmail('');
      setRole(UserRoleEnum.MITARBEITER);
      setPassword(''); // Clear password for new user form
    }
    setFirstNameError('');
    setLastNameError('');
    setEmailError('');
    setPasswordError(''); // Clear password error
  }, [userToEdit, isOpen]); // Reset when modal opens or userToEdit changes

  const validateForm = () => {
    let isValid = true;
    if (!first_name.trim()) {
      setFirstNameError('Vorname ist erforderlich.');
      isValid = false;
    } else {
      setFirstNameError('');
    }

    if (!last_name.trim()) {
      setLastNameError('Nachname ist erforderlich.');
      isValid = false;
    } else {
      setLastNameError('');
    }

    if (!email.trim()) {
      setEmailError('E-Mail ist erforderlich.');
      isValid = false;
    } else if (!/\S+@\S+\.\S+/.test(email)) { // Basic email format validation
      setEmailError('Ungültiges E-Mail-Format.');
      isValid = false;
    } else {
      setEmailError('');
    }

    // Password is only required for new users
    if (!userToEdit && !password.trim()) {
      setPasswordError('Passwort ist erforderlich.');
      isValid = false;
    } else {
      setPasswordError('');
    }

    return isValid;
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (validateForm()) {
      onSubmit({ first_name, last_name, email, role, password }); // Pass first_name, last_name
    }
  };

  const title = userToEdit ? 'Benutzer bearbeiten' : 'Neuen Benutzer erstellen';

  const roleOptions = [
    { value: UserRoleEnum.ADMIN, label: 'Admin' },
    { value: UserRoleEnum.MITARBEITER, label: 'Mitarbeiter' },
  ];

  return (
    <Modal isOpen={isOpen} onClose={onClose} title={title} className="max-w-md">
      <form onSubmit={handleSubmit} className="p-0">
        <div className="space-y-4">
          <Input
            id="userFirstName"
            label="Vorname"
            type="text"
            value={first_name} // Use first_name
            onChange={(e) => setFirstName(e.target.value)}
            placeholder="Max"
            error={firstNameError}
          />
          <Input
            id="userLastName"
            label="Nachname"
            type="text"
            value={last_name} // Use last_name
            onChange={(e) => setLastName(e.target.value)}
            placeholder="Mustermann"
            error={lastNameError}
          />
          <Input
            id="userEmail"
            label="E-Mail"
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            placeholder="max.mustermann@example.com"
            error={emailError}
          />
          {!userToEdit && ( // Only show password field for new users
            <Input
              id="userPassword"
              label="Passwort"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="********"
              error={passwordError}
            />
          )}
          <Select
            id="userRole"
            label="Rolle"
            options={roleOptions}
            value={role}
            onChange={(e) => setRole(e.target.value as UserRoleEnum)}
          />
        </div>
        <div className="p-4 border-t border-gray-200 mt-6 flex justify-end space-x-3">
          <Button variant="outline" onClick={onClose} type="button">
            Abbrechen
          </Button>
          <Button variant="success" type="submit">
            Speichern
          </Button>
        </div>
      </form>
    </Modal>
  );
};

