}

export enum UserRoleEnum {
  ADMIN = 'ADMIN', // Changed to uppercase for consistency with DB enum
  MITARBEITER = 'MITARBEITER', // Changed to uppercase for consistency with DB enum
  KUNDE = 'KUNDE', // Added new role
}

// Interface for the profile data stored in our custom `profiles` table
export interface Profile {
  id: string; // Corresponds to auth.users.id
  email: string;
  first_name: string; // Changed to snake_case
  last_name: string;  // Changed to snake_case
  role: UserRoleEnum;
  customer_id: string | null; // Nullable for Admin/Mitarbeiter
