}

export interface UserTableData {
  id: string;
  avatarInitials: string; // Derived from first_name and last_name, or from profile
  avatarColor: string;    // Derived from profile
  name: string; // Derived from first_name and last_name for display in table
  first_name: string; // Changed to snake_case
  last_name: string;  // Changed to snake_case
  email: string;
  role: UserRoleEnum;
  customer_id: string | null; // Added for UserTableData to potentially link to customers
  createdAt: string;
  password?: string; // Optional password for new user creation in UserManagement
}

