import React, { useState, useEffect } from 'react';
import Card from '../components/Card';
import Table, { Column } from '../components/Table';
import Button from '../components/Button';
import Avatar from '../components/Avatar';
import UserFormModal from '../components/UserFormModal'; // New modal for add/edit user
import UserDeleteConfirmationModal from '../components/UserDeleteConfirmationModal'; // New modal for delete confirmation
import { PlusIcon, EditIcon, TrashIcon, UserPlusIcon } from '../components/Icons';
import { UserTableData, UserRoleEnum, Profile } from '../types';
import { REFERENCE_DATE } from '../constants';
import { supabase } from '../App'; // Import Supabase client

interface UserManagementProps {
  // Added currentUserRole as it's passed from App.tsx, though not directly used in component logic yet.
  currentUserRole: UserRoleEnum;
}

const UserManagement: React.FC<UserManagementProps> = ({ currentUserRole }) => {
  const [users, setUsers] = useState<UserTableData[]>([]);
  const [loadingUsers, setLoadingUsers] = useState(true);
  const [showUserFormModal, setShowUserFormModal] = useState(false);
  const [userToEdit, setUserToEdit] = useState<UserTableData | null>(null); // State to hold user being edited
  const [showDeleteConfirmationModal, setShowDeleteConfirmationModal] = useState(false);
  const [userToDeleteId, setUserToDeleteId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const fetchUsers = async () => {
    setLoadingUsers(true);
    setError(null);
    const { data, error: fetchError } = await supabase
      .from('profiles')
      .select('*')
      .neq('role', UserRoleEnum.KUNDE); // Only fetch Admin and Mitarbeiter for management

    if (fetchError) {
      console.error('Error fetching users:', fetchError);
      setError('Fehler beim Laden der Benutzer.');
      setUsers([]);
    } else if (data) {
      const mappedUsers: UserTableData[] = data.map(profile => {
        const initials = profile.avatar_initials ||
          (profile.first_name && profile.last_name
            ? `${profile.first_name.charAt(0)}${profile.last_name.charAt(0)}`.toUpperCase()
            : '?');
        const color = profile.avatar_color || 'bg-gray-400';

        return {
          id: profile.id,
          avatarInitials: initials,
          avatarColor: color,
          name: `${profile.first_name || ''} ${profile.last_name || ''}`.trim(),
          first_name: profile.first_name,
          last_name: profile.last_name,
          email: profile.email,
          role: profile.role,
          customer_id: profile.customer_id,
          createdAt: new Date(profile.created_at).toLocaleDateString('de-DE'),
        };
      });
      setUsers(mappedUsers);
    }
    setLoadingUsers(false);
  };

  useEffect(() => {
    fetchUsers();
  }, []); // Fetch users on initial mount

  const handleOpenAddUserModal = () => {
    setUserToEdit(null); // Clear userToEdit for add mode
    setShowUserFormModal(true);
  };

  const handleOpenEditUserModal = (user: UserTableData) => {
    setUserToEdit(user);
    setShowUserFormModal(true);
  };

  const handleCloseUserFormModal = () => {
    setShowUserFormModal(false);
    setUserToEdit(null);
  };

  const handleSubmitUserForm = async (userData: { first_name: string; last_name: string; email: string; role: UserRoleEnum; password?: string }) => {
    setError(null);
    if (userToEdit) {
      // Update existing user
      const updatedAvatarInitials = `${userData.first_name.charAt(0)}${userData.last_name.charAt(0)}`.toUpperCase().slice(0, 2);
      // Retain existing avatar_color if available, otherwise generate a new one
      const avatarColors = ['bg-red-500', 'bg-orange-500', 'bg-purple-500', 'bg-indigo-500', 'bg-blue-500', 'bg-green-500'];
      const updatedAvatarColor = userToEdit.avatarColor || avatarColors[Math.floor(Math.random() * avatarColors.length)];

      const { data, error: updateError } = await supabase
        .from('profiles')
        .update({
          first_name: userData.first_name,
          last_name: userData.last_name,
          email: userData.email,
          role: userData.role,
          avatar_initials: updatedAvatarInitials, // Update initials
          avatar_color: updatedAvatarColor,       // Update color
        })
        .eq('id', userToEdit.id);

      if (updateError) {
        console.error('Error updating user:', updateError);
        setError('Fehler beim Aktualisieren des Benutzers.');
      } else {
        await fetchUsers(); // Refresh the list
        handleCloseUserFormModal();
      }
    } else {
      // Add new user (requires creating auth user first, then profile)
      if (!userData.password) {
        setError('Passwort ist für neue Benutzer erforderlich.');
        return;
      }

      // 1. Create Supabase Auth User
      const { data: authData, error: authError } = await supabase.auth.signUp({
        email: userData.email,
        password: userData.password,
        options: {
          data: { // Custom data for the auth user (can be used in webhooks for profile creation)
            first_name: userData.first_name,
            last_name: userData.last_name,
            role: userData.role,
            avatar_initials: `${userData.first_name.charAt(0)}${userData.last_name.charAt(0)}`.toUpperCase().slice(0, 2),
            avatar_color: ['bg-red-500', 'bg-orange-500', 'bg-purple-500', 'bg-indigo-500', 'bg-blue-500', 'bg-green-500'][Math.floor(Math.random() * 6)],
          },
        },
      });

      if (authError) {
        console.error('Error creating auth user:', authError.message);
        setError(`Fehler beim Erstellen des Benutzers: ${authError.message}`);
        // If email already exists, Supabase auth.signUp returns "User already registered" error
        // A more robust solution would check if the profile exists and link, or prompt user.
        return;
      }

      if (authData.user) {
        // If auth user created, create profile.
        // NOTE: In a production app, profile creation should ideally be handled by a Supabase trigger
        // on auth.users INSERT, to ensure consistency and prevent client-side bypass.
        const avatarColors = ['bg-red-500', 'bg-orange-500', 'bg-purple-500', 'bg-indigo-500', 'bg-blue-500', 'bg-green-500'];
        const randomColor = avatarColors[Math.floor(Math.random() * avatarColors.length)];

        const newProfile: Omit<Profile, 'created_at'> = {
          id: authData.user.id,
          email: userData.email,
          first_name: userData.first_name,
          last_name: userData.last_name,
          role: userData.role,
          customer_id: null, // New users are not linked to customers by default
          avatar_initials: `${userData.first_name.charAt(0)}${userData.last_name.charAt(0)}`.toUpperCase().slice(0, 2),
          avatar_color: randomColor,
        };

        const { error: profileError } = await supabase
          .from('profiles')
          .insert(newProfile);

        if (profileError) {
          console.error('Error creating profile:', profileError);
          setError('Benutzer erstellt, aber Profilerstellung fehlgeschlagen.');
          // Consider rolling back auth user creation or flagging for manual fix.
        } else {
          await fetchUsers(); // Refresh the list
          handleCloseUserFormModal();
        }
      } else {
        setError('Keine Benutzerdaten nach der Registrierung.');
      }
    }
  };

  const handleOpenDeleteConfirmation = (userId: string) => {
    setUserToDeleteId(userId);
    setShowDeleteConfirmationModal(true);
  };

  const handleConfirmDelete = async () => {
    if (!userToDeleteId) return;
    setError(null);

    // In a real application, you would also need to delete the user from auth.users.
    // This typically requires admin privileges and should be done via a secure backend function
    // or a Supabase Edge Function to prevent exposing sensitive API keys or enabling privilege escalation.
    // For this mock/frontend-focused app, we're only deleting the profile entry.

    const { error: deleteError } = await supabase
      .from('profiles')
      .delete()
      .eq('id', userToDeleteId);

    if (deleteError) {
      console.error('Error deleting user:', deleteError);
      setError('Fehler beim Löschen des Benutzers.');
    } else {
      await fetchUsers(); // Refresh the list
    }
    setShowDeleteConfirmationModal(false);
    setUserToDeleteId(null);
  };

  const handleCloseDeleteConfirmation = () => {
    setShowDeleteConfirmationModal(false);
    setUserToDeleteId(null);
  };

  // userTableData is derived from 'users' state, which already has fallbacks
  const userTableData: UserTableData[] = users;

  const columns: Column<UserTableData>[] = [
    {
      key: 'name',
      header: 'BENUTZER',
      render: (item: UserTableData) => (
        <div className="flex items-center">
          <Avatar initials={item.avatarInitials} color={item.avatarColor} size="md" className="mr-3" />
          <p className="font-medium text-gray-900">{item.name}</p>
        </div>
      ),
    },
    { key: 'email', header: 'E-MAIL' },
    {
      key: 'role',
      header: 'ROLLE',
      render: (item: UserTableData) => (
        <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium
          ${item.role === UserRoleEnum.ADMIN ? 'bg-red-100 text-red-800' : 'bg-blue-100 text-blue-800'}`}
        >
          {item.role}
        </span>
      ),
    },
    { key: 'createdAt', header: 'ERSTELLT' },
    {
      key: 'id',
      header: 'AKTIONEN',
      render: (item: UserTableData) => (
        <div className="flex items-center space-x-3">
          <button
            onClick={(e) => { e.stopPropagation(); handleOpenEditUserModal(item); }}
            className="text-gray-500 hover:text-blue-600"
            aria-label={`Benutzer ${item.name} bearbeiten`}
          >
            <EditIcon className="h-5 w-5" />
          </button>
          <button
            onClick={(e) => { e.stopPropagation(); handleOpenDeleteConfirmation(item.id); }}
            className="text-gray-500 hover:text-red-600"
            aria-label={`Benutzer ${item.name} löschen`}
          >
            <TrashIcon className="h-5 w-5" />
          </button>
        </div>
      ),
      className: 'text-right',
    },
  ];

  const userToDelete = users.find(u => u.id === userToDeleteId);

  if (loadingUsers) {
    return (
      <div className="p-6 md:p-8 lg:p-10 text-center text-gray-700">
        Lade Benutzer...
      </div>
    );
  }

  return (
    <div className="p-6 md:p-8 lg:p-10">
      <div className="flex justify-between items-center mb-2">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Benutzerverwaltung</h1>
          <p className="text-gray-600">Verwalten Sie alle Systembenutzer an einem Ort</p>
        </div>
        <Button variant="success" icon={UserPlusIcon} onClick={handleOpenAddUserModal}>
          Neuer Benutzer
        </Button>
      </div>

      {error && (
        <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded relative mb-4" role="alert">
          <strong className="font-bold">Fehler!</strong>
          <span className="block sm:inline"> {error}</span>
        </div>
      )}

      <Card className="mt-8">
        <h2 className="text-xl font-semibold text-gray-900 mb-4">Systembenutzer ({users.length})</h2>
        <Table data={userTableData} columns={columns} />
      </Card>

      <UserFormModal
        isOpen={showUserFormModal}
        onClose={handleCloseUserFormModal}
        onSubmit={handleSubmitUserForm}
        userToEdit={userToEdit}
      />

      <UserDeleteConfirmationModal
        isOpen={showDeleteConfirmationModal}
        onClose={handleCloseDeleteConfirmation}
        onConfirm={handleConfirmDelete}
        userNameToDelete={userToDelete ? `${userToDelete.first_name || ''} ${userToDelete.last_name || ''}`.trim() : ''}
      />
    </div>
  );
};

export default UserManagement;

